INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4583','Не сумуй, дитино','Музика: Ігор Особік Слова: Олександр Олесь. Виконує: Ігор Особік','uk','ukraine_1991',NULL,NULL,'Збірник пісень Студентського Братства Львівської політехніки.- Львів, 2000','* У варіанті пісні Ігора Особіка, поданому у "Збірнику пісень Студентського Братства Львівської політехніки", даного куплета нема. Автор даного (останнього) куплету: Богдан Яцун. Використано акорд: А5 [x 0 2 2 x x]. Акорди (варіант 2) надав Ярослав Юрчишин, спростив Bohdanko.','Не сумуй, дитино,   що немає тата,
Мабуть, його в полі    стримала розплата.

Він прийде додому, принесе гостинця -
Повні поли маків і перлин для синця.

Не лютуй, що тато не прийшов на свято,
Мабуть, його в полі стримала розплата.

Ти ж хіба не бачив,   як вояк-чужинець
Все питав у мене: "Кто он? Украінєц?"

Як я від удару   серед хати впала,
Як він бив ногами,   як я проклинала.

Не журися, сину, що немає тата,
Мабуть, його в полі стримала розплата.

Виростай, мій сину, будь міцний, як криця.
Виростеш, - скажу я, - де лежить рушниця,

Де лежать набої, де лежить граната.
Не сумуй же, сину, що немає тата.

Щоб не знав спокою окупант-чужинець, *
Щоб боявся навіть слова "українець"!

Акорди (варіант 2, спрощений):
Не сумуй, дитино,   що немає тата,
Мабуть, його в полі    стримала розплата.
Ти ж хіба не бачив,   як вояк-чужинець
Все питав у мене: "Кто он? Украінєц?"
Як я від удару   серед хати впала,
Як він бив ногами, як я проклинала.','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4583'), datetime('now')),datetime('now'));
