INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_460287','Виряжала мати сина','Українська народна пісня','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'Літопис УПА, том 25, ст. 208.','*Виряжала — так в оригіналі, пропонуєтся як варіант: "виряджала"; **A — цей акорд слід брати з баре: [555775]','Виряжала* мати сина
Під Крути до бою
Розчесала кучерики      |
Понад головою.          |(2)

Іди, іди, мій синочку, —
В бою не здавайся,
Як побореш вороженьків, |
Додому вертайся.        |(2)

Іду, іду, моя мати, —
Вчиню твою волю,
А ти ходи й проси Бога, |
Щоб вернувся з бою.     |(2)

Ждала, ждала мати сина,
Під Крути ходила
Та й шукала між трупами |
Найменшого сина.        |(2)

Ой пізнала Стара мати
Головоньку сина,
Проклинаючи, колише,    |
Тай заголосила.         |(2)

Люляй, люляй мій синочку,
Тож я твоя мати -
Сину Рідний... Боже милий...|
Вороже проклятий!           |(2)
Акорди:

Виряджала мати си-и-ина-а
Під Крути до бо-о-ою
Розчесала-а куче-ери-ики
F     G     A**
Понад голо-ово-ою.','[''pisni.org.ua'', ''cat:istorychni'', ''cat:kruty'', ''cat:povstanski'', ''Історичні пісні'', "Пісні пам''яті Героїв бою під Крутами", ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_460287'), datetime('now')),datetime('now'));
