INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_463736','Ой у полі могила *','Українська народна пісня. Виконує: Жанна Боднарук','uk','ukraine_before_1917',NULL,NULL,'http://nashe.com.ua/',NULL,'Ой у полі могила
З вітром говорила:
"Повій, буйнесенький вітре,
Щоб я не марніла."

Ой у полі річка,
Через річку кладка.
Ой не кидай, козаченьку,
Рідненького батька.

Бодай тая річка
Куширом заросла,
Вона мене козаченька
В чужий край занесла.

Бодай тая річка
Риби не плодила,
Вона мене молодого
Зі світу згубила.

Ой у полі могила
З вітром говорила:
"Повій, буйнесенький вітре,
Щоб я не марніла."

Останні два рядки кожного куплету повторюються двічі.','[''pisni.org.ua'', ''cat:all-ukraine'', ''Загальноукраїнські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_463736'), datetime('now')),datetime('now'));
