INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_45981','Їхали козаки','Українська народна пісня. Виконує: Кубанський Козачий Хор','uk','ukraine_before_1917',NULL,NULL,'1. Співаник тернопільського туристичного клубу "Кристал" 2. Текст доповнив та виправив Станіслав','* - ясно, що самі козаки мали співати "погодилась", але тут йде гра під російского слухача.','Їхали козаки із Дону додому,
Підманули Галю, забрали з собою.

Ой, ти Галю, Галю молодая.
Підманули Галю, забрали з собою.

Ой, поїдем, Галю, з нами, козаками,
Краще тобі буде, чим у рідной мами.

Ой, ти, Галю, Галю молодая
Краще тобі буде, чим у рідной мами.

Галя согласилась*, на віз підчепилась,
Та й повезли Галю темними лісами.

Ой, ти Галю, Галю молодая.
Та й повезли Галю темними лісами.

Везли-везли Галю темними лісами,
Прив''язали Галю до сосни косами.

Ой, ти Галю, Галю молодая.
Прив''язали Галю до сосни косами.

Розбрелись по лісу, назбирали хмизу,
Підпалили сосну від гори до низу

Ой, ти Галю, Галю молодая.
Підпалили сосну від гори до низу

Горить сосна, горить, горить та й палає.
Кричить Галя криком, кричить розмовляє.

Ой, ти Галю, Галю молодая.
Кричить Галя криком, кричить розмовляє.

Ох, хто в лісі чує, нехай порятує,
А хто дочок має, нехай научає.

Ой, ти Галю, Галю молодая.
А хто дочок має, нехай научає.

А хто дочок має, нехай научає.
Та й темної ночі гулять не пускає.

Ой, ти Галю, Галю молодая.
Та й темної ночі гулять не пускає.

Обізвався козак: "Я в полі ночую,
Я твій голосочок здалека почую".

Ой, ти Галю, Галю молодая.
Я твій голосочок здалека почую.','[''pisni.org.ua'', ''cat:narodni'', ''cat:zhartivlyvi'', ''Народні пісні'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_45981'), datetime('now')),datetime('now'));
