INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_463333','Здрастуй, друже','Музика: Микола Сацура Слова: В. Ковальчук. Виконує: Сябри','uk','ukraine_1991',NULL,NULL,'http://maria.sarov.info','Пісня написана до ювілею композитора Миколи Мозгового. Виконує білоруський ансамбль "СЯБРИ"','Я приїхав з Білорусі
До своїх шановних друзів.
Час такий, що зустрічаться
Стало нам великим щастям.
Ось тому сьогодні з Вами
Ми зустрілись, як у мами,
І сердечнії розмови
На одній ведемо мові.

Приспів:
Здрастуй, друже, здрастуй, друже,
Обнімаю - серце тенька,
Здрастуй, ти, моє серденько.
Ми недавно розлучились,
Скільки літ вже пролетіло,
Але ми давно навчились
Нашу дружбу берегти.

Наша зустріч - сонця промінь,
Буде жить про неї спомин.
Ми ж землі одної діти,
Всі ми схожі, поглядіте.
Хто з нас старший, хто молодший?
Де у кого скільки грошей?
Нам немає тут різниці,
Нам не треба тут різниться.

Приспів.

Все пливе, мов за водою,
Вічно те, що за любов''ю.
Хай горить любов-багаття,
Будем жить, як рідні браття.
Хай пісні у світ лунають,
Хай про нас у світі знають.
Будем, браття, шануватись,
Край свій рідний прославляти.

Край, мій рідний край,
Пісенний край завзяття і труда,
Ти - моя любов,
Ти - рідна матінко, моя земля!

Приспів.

Будьмо! Будьмо! Будьмо!','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_463333'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_463333','Здрастуй, друже','Я приїхав з Білорусі
До своїх шановних друзів.
Час такий, що зустрічаться
Стало нам великим щастям.
Ось тому сьогодні з Вами
