INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_46287','Вітай, Ісусе','Слова: Віктор Матюк','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Вітай, Ісусе, з Пречистой Діви
Зроджений.
Вітай нам, Боже, у людськім тілі
З''явлений.

Ти добротою нам всім красший
Синами
І милосердя границь немає
Над нами.

Ти в славі рівний Отцю і Духу
Святому,
Чому ж зійшов Ти до нас в укриттю
Такому?

Днесь Твоєй слави ніхто не видить
В яскині,
А твоя сила сухой не зломить
Билини.

А Ти на нужду і на терпіння
Й не глянеш,
Но чим убожий, тим нам дорожчий
Ся станеш.

Ти сам смиренням з нас грішних здіймеш
Окови,
А в наших серцях заложиш царство
Любови.

О Агнче Божий, ми Тя о тоє
Днесь просим:
І наші серця Тобі на жертву
Приносим.

Не опусти їх з Своєй святої
Опіки.
Царствуй в них радо з Отцем і Духом
Навіки','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christian'', ''cat:kolyadky'', ''Церковні пісні'', ''Пісні на християнську тематику'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_46287'), datetime('now')),datetime('now'));
