INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_461535','Ой казала мені мати','Українська народна пісня. Виконує: Оксана Петрусенко, Квітка Цісик','uk','ukraine_before_1917',NULL,NULL,'1. Струни серця. Українські народні пісні про кохання. Київ, Держлітвидав, 1969. 2. Українські співанки. Упорядник Степан Налєпа. — Львів: Сполом, 2007. — 404 с.','Арія Одарки з опери Семена Гулака-Артемовського "Запорожець за Дунаєм".','Ой казала мені мати
І приказувала,
Щоб я хлопців у садочок
Не принаджувала.
Ой мамо, мамо, мамо,
Не принаджувала!

Посилала мене мати
До криниченьки,
"Та принеси, моя доню,
Та водиченьки".
Ой мамо, мамо, мамо,
Та водиченьки!

Ой пішла я до ставочка,
Забарилася:
На козака молодого
Задивилася!
Ой мамо, мамо, мамо,
Задивилася!

Розмовляла з козаченьком
Цілу ніченьку.
Ой пом''яла фартушину
Та й новесеньку!
Ой мамо, мамо, мамо,
Та й новесеньку!

Ждала, ждала мене мати,
Не діждалася:
А я собі у ставочу
Полоскалася!
Ой мамо, мамо, мамо,
Полоскалася!','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_461535'), datetime('now')),datetime('now'));
