INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_463583','Не вимовлю ні слова','Музика: Олександр Бурміцький Слова: Микола Луків. Виконує: Анатолій Горчинський, Гурт Осокори','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Не вимовлю ні слова. Помовчу.
А дощ іде. А вітер хилить клени.
На серці так бентежно - до плачу.
Присядь, кохана, ближче біля мене.

Нехай не ятрять прикрощі душі,
Нехай квітує щирість поміж нами...
Присядь. Послухай. Шелестять дощі
Про те, чого не вимовиш словами

Отак. Спасибі. Чуєш, як шумить,
Як шелестить, кипить травнева злива?
Увесь наш вік - одна жагуча мить,
Я б так хотів, щоб ти була щаслива!

Нехай не ятрять прикрощі душі,
Нехай квітує щирість поміж нами...
Присядь. Послухай. Шелестять дощі
Про те, чого не вимовиш словами','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_463583'), datetime('now')),datetime('now'));
