INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_463838','Знов я у гори іду','Музика: Микола Мозговий Слова: Юрій Рибчинський. Виконує: Назарій Яремчук, Микола Мозговий, Павло Мрежук, Василь Зінкевич','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Знов мені наснилися зажурені лелеки
І мене покликали додому уві сні,
Добрий день, Карпати, добрий день, мої смереки,
Добрий день вам, гори чарівні!

Тут веселий вітер в''є гніздо на полонині,
Тут зустрів уперше я сердець людських тепло,
Тут мої краяни, тут життя мого коріння,
Тут моє пісенне джерело!

Приспів:
Знов я у гори іду,
А назустріч потоки, мов роки.
Знов я у гори іду,
Щоб зустріти весну молоду.
Знов я у гори іду,
А ті гори, мов доля високі,
Я до них, я до них, я до них іду,
Наче на сповідь іду.

Над горами місяць, мов вівчар далекозорий,
Нагадає він мені, це свідок мовчазний,
Як моє кохання заблукало в першій зорі,
В чистих небесах юнацьких мрій.

Приспів. (2)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_463838'), datetime('now')),datetime('now'));
