INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4582430','Ангели гідності','Музика: Пісня дня Слова: Пісня дня','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми пам''ятаєм їхній крок,
Крізь дим летіли до зірок.
Вони тримають в небі щит,
Щоб захистити вільний світ!

Приспів:
Ангели гідності крила розкрили,
Нам додають неймовірної сили!
Небесній Сотні вдячні за свободу!
Це - вічна варта нашого народу!

Це наша сила і священа лють,
Герої Майдану у серцях живуть!
Небесна варта стоїть, як стіна,
Поки триває ця люта війна!..

Приспів.

Небесна Сотня стоїть за спиною,
Закрила країну живою стіною!
Ми вистоїм точно! Ми зможемо все!
Бо пам''ять героїв до цілі несе!

Приспів.

Герої не вмирають!
Вони живуть в наших серцях!','[''pisni.org.ua'', ''cat:euromaydan'', ''Пісні Євромайдану'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4582430'), datetime('now')),datetime('now'));
