INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_464634','Я святкую життя','Музика: Ольга Богомолець Слова: Ірина Жиленко. Виконує: Ольга Богомолець','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я святкую життя, хвалю свою спрагу, свій голод юний.
Слава Богу, я ще люблю, слава Богу, я ще воюю.
Я святкую терпку зажуру цих каштанів на тлі небес.
І солодку мою тортуру - безнадійно кохать тебе.

Це тюльпани з вогню і з золота піднімаю і п''ю мій любий
За твою кучеряву голову, за твої недосяжні губи,
П''ю за нашу осінню дружбу, і за кави гіркий нектар,
За веселу твою  байдужість до моїх поетичних чар,
За роки котрі минули, або ми проминули їх,
І за скріпки тоненьких вулиць, і за перший на скронях сніг.

Я святкую життя, хвалю свою спрагу, свій голод юнний.
Слава Богу, я ще люблю, слава Богу, я ще воюю.
Я святкую терпку зажуру цих каштанів на тлі небес.
І солодку мою тортуру - безнадійно кохать тебе.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_464634'), datetime('now')),datetime('now'));
