INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_463030','Новий рік іде','Музика: Анатолій Карпенко Слова: Анатолій Карпенко. Виконує: Жанна Боднарук, Анатолій Карпенко','uk','ukraine_1991',NULL,NULL,NULL,'Співає Жанна Боднарук разом з Анатолієм Карпенко та Андрійком Карпенко Альбом "Разом з друзями"','Як швидко збігає час,
І знову іде до нас чудовий день,
Де все казкове.
Немов чарівним крилом,
Розсріблений за вікном,
Сніг іскриться і сяє ялинка святкова.

Чекають свята на землі
Птахи, звірята, діточки малі.

Приспів:
Новий рік іде, щоб всі бажання збулись,
Хай в житті здійсниться
Цілий світ дитячих мрій,
Не сумуй про те,
Що не повернеш рік минулий,
Краще все прекрасне хай з тобою іде
В Новий рік!

На струнах душі бринить
Найкраща солодка мить,
Годинник б''є, і вже дванадцять.
Хай щастя прийде нове,
Кохання нехай живе,
Щоб в житті друзі довго могли зустрічатись.

Чарівна ніч, зірки горять,
Як в дивнім сні ялиночки стоять.

Приспів. (2)

Новий рік іде...','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_463030'), datetime('now')),datetime('now'));
