INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_46583','Ой пливе човен по росі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна Лірика.',NULL,'Ой пливе совен по росі,
Плаче Марусенька по косі:
- Ой косо ж моя, ой руса ж моя,
Ти ж мені краса була.
Ой як я тебе розпущу,
Свого батенька засмучу,
Ой косо ж моя, ой руса ж моя,
Ти ж мені краса була.
Ой як я тебе носила,
То ти мене красила,
Ой як я тебе розстелю,
Свого Степана звеселю.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_46583'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_46583','Ой пливе човен по росі','Ой пливе совен по росі,
Плаче Марусенька по косі:
- Ой косо ж моя, ой руса ж моя,
Ти ж мені краса була.
Ой як я тебе розпущу,
Свого батенька засмучу,
Ой косо ж моя, ой руса ж моя,
Ти ж мені краса була.
Ой як я тебе носила,
То ти мене красила,
Ой як я тебе розстелю,
Свого Степана звеселю.');
