INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4581083','Ліпші подружки','Музика: Ivan Klymenko, BangBlazeMusic, Олег Шкарпета (Шугар) Слова: Ivan Klymenko, Олег Шкарпета (Шугар), Владислава Кіцелюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми сиділи до самого ранку,
Слухали сумні треки з TіkTok-y.
Тобі посипали сіллю на ранку,
Та знай, що я буду з тобою!
Після ночі наступить світанок,
Подивись, все не так вже й погано!
Зробим сердечко із рук,
Жити легше, коли поруч друг!

Приспів:
Ми можемо разом плакати під пісні   |
І в чистому одязі валятись в траві! |
Ми можем співати голосно уночі,     |
А люди з балконів - наші глядачі.   | (2)

Ми можемо разом усе, усе, усе!
Ми можемо разом усе!
Ми можемо разом усе, усе, усе!
Ми можемо разом усе!

А ми ЛП-шки - ліпші подружки,
Сережки носим однакові,
І ходим по тим самим стежкам!
А ми - бестфренди,
Знаєм секретні моменти!
Їх пронесем через життя
Аж до хепі-енду!
Прошу тебе, не забувай мене,
Бо я ношу тебе у пам''яті кожен день.

Приспів.','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4581083'), datetime('now')),datetime('now'));
