INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_465236','Через поле широкеє','Музика: народна Слова: кант. Виконує: Бандурна Розмова, Григорій Гребініченко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує хорова група Заслуженого народного ансамблю пісні і танцю України "Дарничанка". Художній керівник і диригент - Заслужений працівник культури України, професор КНУКіМ П. Андрійчук. Солісти: Заслужений працівник культури України - Григорій Гребініченко, В. Набок.','Через поле широкеє,
Та через море глибокеє,
Туди йшла пречистая,
Та пречистая, Божа мати.

Де Христа взяли,
На хрест розпняли,
Розтягли руки -
Прибивали.

Славімо Тебе,
Сине Божий,
А Твоя ласка |
Нам поможе.  | (2)','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_465236'), datetime('now')),datetime('now'));
