INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_465931','Ой у полі криниченька','(З неї вода протікає...). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Народні перлини. Українські народні пісні. Київ, Державне видавництво художньої літератури, 1961.',NULL,'Ой у полі криниченька,
З неї вода протікає.       | (2)
Ой там чумак сірі воли пасе
Та з криниці напуває.

Воли ревуть, води не п''ють.
Бо в Крим доріженьку чуют. | (2)
Ой бог знає та й бог відає,
Де чумаченьки ночують.

А ночують чумаченьки
В кримськім степу при дoлині, | (2)
Розпустили та сірі воли
По зеленій муравині.

Бодай же ви, сірі воли,
Та в Крим по сіль не сходили. | (2)
Ой як же ви мені, та молодому,
Ой та жалю наробили!..

Ой умер же чумаченько,
Ой та в неділеньку вранці, | (2)
Ой поховали та чумаченька
Та в зеленому байраці.

Насипали над чумаком
Та високую могилу,     | (2)
Ой посадили та в головоньках
Та червоную калину.

Полинула зозуленька
Та й сказала "ку-ку!", | (2)
Ой подай, сину, подай, орле,
Та хоч праву, праву руку.

Ой рад же я, моя мати,
Та й обидві подати,    | (2)
Ой та налягла сирая земля -
Ой та трудненько підняти.','[''pisni.org.ua'', ''cat:chumacki'', ''Чумацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_465931'), datetime('now')),datetime('now'));
