INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_465981','Ой у полі край дороги','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Народні перлини. Українські народні пісні. Київ, Державне видавництво художньої літератури, 1961.',NULL,'Ой у полі край дороги
Пшениченька яра,
Там молода дівчинонька
Пшениченьку жала.

Та болять ручки, та болять ніжки,
Та пшениченьку жнучи,
Та вже ж мені надокучило,
Та миленького ждучи.

Та нема ж мого миленького,
Та нема ж мого пана,
Та вже ж моя постіль біла
Пилочком припала.

Та нема ж мого миленького,
Та нема ж мого сонця,
Та вже ж менi надокучило,
Сидячи в віконця.

Гей, із-за гори, із-за кручі
Скриплять вози йдучи,
Вози скриплять, ярма риплять,
Воли ремигають.

Попереду мій миленький
В сопілочку грає,
Сопілочка з барвіночка,
Калинове денце -
Вийди ж, мила, чорнобрива,
Потіш моє серце!','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_465981'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_465981','Ой у полі край дороги','Ой у полі край дороги
Пшениченька яра,
Там молода дівчинонька
Пшениченьку жала.

Та болять ручки, та болять ніжки,
Та пшениченьку жнучи,
Та вже ж мені надокучило,
Та миленького ждучи.

Та нема ж мого миленького,
Та нема ж мого пана,
Та вже ж моя постіль біла
Пилочком припала.

Та нема ж мого миленького,
Та нема ж мого сонця,
Та вже ж менi надокучило,
Сидячи в віконця.

Гей, із-за гори, із-за кручі
Скриплять вози йдучи,
Вози скриплять, ярма риплять,
Воли ремигають.

Попереду мій миленький
В сопілочку грає,
Сопілочка з барвіночка,
Калинове денце -
Вийди ж, мила, чорнобрива,
Потіш моє серце!');
