INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_467535','Ти ждеш мене','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Струни серця. Українські народні пісні про кохання. Київ, Держлітвидав, 1969.',NULL,'У дні весняні, дні осінні
Ти, серце ьідне, не смутись.
Отут, в низенькій цій хатині,
Моя любов жила колись.

Як проводжала, виглядала,
Як ми журилися в дворі,
Крізь сльози очі твої сяли,
Як день весняний на зорі.

Як подавала воду пити,
Немовби серце віддала.
І знову бачу теплі віти
І рідний сум твого чола.

І сняться очі ті дівочі,
Хай спогад милий промайне,
І все здається: в темні ночі
Ти ждеш мене, ти ждеш мене.','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_467535'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_467535','Ти ждеш мене','У дні весняні, дні осінні
Ти, серце ьідне, не смутись.
Отут, в низенькій цій хатині,
Моя любов жила колись.

Як проводжала, виглядала,
Як ми журилися в дворі,
Крізь сльози очі твої сяли,
Як день весняний на зорі.

Як подавала воду пити,
Немовби серце віддала.
І знову бачу теплі віти
І рідний сум твого чола.

І сняться очі ті дівочі,
Хай спогад милий промайне,
І все здається: в темні ночі
Ти ждеш мене, ти ждеш мене.');
