INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_467338','Мене забудь, моя дівчино','Музика: Леонід Мазур Слова: Степан Руданський. Виконує: Леонід Мазур','uk','ukraine_before_1917',NULL,'1854','Струни серця. Українські народні пісні про кохання. Київ, Держлітвидав, 1969.','Написано 19.02.1854 р. В відеоролику використані фото картин відомого українського художника Володимира Донатовича Орловського.','Мене забудь, моя дівчино!
Спокійно жий, щаслива будь,
Цвіти, як рожа, як калина, -
Мене забудь, мене забудь!..

Мене забудь - і тяжким смутком
Не розбивай біленьку грудь:
Шукай собі коханка хутко,
Мене забудь, мене забудь!

Мене забудь, мене не треба!
Та якби я коли-небудь
Тебе забув... о боже з неба,
Мене забудь, мене забудь!..','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_467338'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_467338','Мене забудь, моя дівчино','Мене забудь, моя дівчино!
Спокійно жий, щаслива будь,
Цвіти, як рожа, як калина, -
