INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_46636','За городом качки пливуть','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна Лірика.',NULL,'З городом качки пливуть,
Каченята крячуть...
Вбогі дівки заміж ідуть,
А багаті плачуть.

Вбогі дівки заміж ідуть
З чорними бровами,
А багаті дівки сидять
З кіньми та волами.

"Чи ти чула, дівчинонько,
Як я тебе кликав,
Через твоє подвір''ячко
Сивим конем їхав?" -

"Ой хоч чула, хоч не чула,
Не обзивалася:
Темна нічка-петрівочка, -
Вийти боялася!" -

"Ой не бійся, дівчинонько,
Не бійся нічого,
Бо я хлопець молоденький
Не зрадив нікого!" -

"Ой не хоче твоя мати
Мене, бідну, знати,
Хоче собі багатую
Невістку шукати!" -

"Нащо мені на подвір''ї
Воли та корови,
Як не буде в моїй хаті
Любої розмови!"

Ой десь гуде, ой десь грає,
Скрипка витинає:
Оце вдова своїй доні
Весілля справляє.

Нехай знають, нехай знають,
Де музики грають,
Нехай знають, нехай знають,
Як бідні гуляють!    Фонограма-мінус (mp3)','[''pisni.org.ua'', ''cat:lirychni'', ''cat:narodni'', ''cat:vesilni'', ''Пісні про кохання, ліричні'', ''Народні пісні'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_46636'), datetime('now')),datetime('now'));
