INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_467436','Ой ходила дівчина бережком','Українська народна пісня. Виконує: Кобза','uk','ukraine_before_1917',NULL,NULL,'Народні перлини. Українські народні пісні. Київ, Державне видавництво художньої літератури, 1961.',NULL,'Ой ходила дівчина бережком,           | (2)
Заганяла селезня батіжком:            | (2)
"Іди, іди, селезню, додому.           | (2)
Продам тебе дідові старому".          | (2)
За три копи селезня продала,          | (2)
А за копу дударика найняла:           | (2)
"Заграй мені, дударику, на дуду,      | (2)
Нехай же я своє горе забуду".         | (2)
"Коли б тобі горенько да печаль.      | (2)
То б ти вийшов на вулицю та й кричав; | (2)
А то ж тобі горенька немає,           | (2)
Ой хто ж тобі сі кучері звиває?" -    | (2)
"Була в мене дівчина Уляна,           | (2)
Вона ж мені сі кучері звивала;        | (2)
Була в мене дівчина Орися,            | (2)
Тоді в мене сі кучері вилися;         | (2)
Була в мене дівчина Варвара,          | (2)
Вона ж мені сі кучері порвала.        | (2)
Була в мене дівчина паскуда,          | (2)
Вона ж мені сі куречі поскубла".      | (2)','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_467436'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_467436','Ой ходила дівчина бережком','Ой ходила дівчина бережком,           | (2)
Заганяла селезня батіжком:            | (2)
"Іди, іди, селезню, додому.           | (2)
Продам тебе дідові старому".          | (2)
За три копи селезня продала,          | (2)
А за копу дударика найняла:           | (2)
"Заграй мені, дударику, на дуду,      | (2)
Нехай же я своє горе забуду".         | (2)
"Коли б тобі горенько да печаль.      | (2)
То б ти вийшов на вулицю та й кричав; | (2)
А то ж тобі горенька немає,           | (2)
Ой хто ж тобі сі кучері звиває?" -    | (2)
"Була в мене дівчина Уляна,           | (2)
Вона ж мені сі кучері звивала;        | (2)
Була в мене дівчина Орися,            | (2)
Тоді в мене сі кучері вилися;         | (2)
Була в мене дівчина Варвара,          | (2)
Вона ж мені сі кучері порвала.        | (2)
Була в мене дівчина паскуда,          | (2)
Вона ж мені сі куречі поскубла".      | (2)');
