INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_467137','Син','Музика: Анатолій Матвійчук Слова: Анатолій Матвійчук. Виконує: Алла Кудлай','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Відлинули у даль весняні грози,
Осінні хмари небо затягли,
Так непомітно став мій син дорослим,
Я навіть і не зчулася коли.
Я йому в житті не шкодувала
Уваги й  материнського тепла,
І тільки Матір Божу я благала
Щоби його на світі берегла.

Приспів:
У кожної мами
Турбота єдина - про сина.
Щодалі з роками
Надіється мама на сина.
І все віддала би на світі
Для нього, для сина.
Для матері син -
Найрідніша людина!

В житті буває і любов, і зрада,
І світла радість, і печаль гірка,
Рятує душу мамина порада,
Лікує серце мамина рука.
І хай життя нас розлучає часто
І ні нa мить спинитись не дає,
Я знову долі дякую за щастя,
Що в мене син, а в мене мама є.

Приспів.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''cat:pro-ditey'', ''Пісні про любов до батьків'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_467137'), datetime('now')),datetime('now'));
