INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_469889','Колискова','Музика: Лілія Остапенко Слова: Лілія Остапенко. Виконує: Лілія Остапенко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Спи, моя кохана,
Спи, моя безсонна,
Моя зірка рання,
Моя люба доня.

Спи, красуня мила,
Ластівка крилата.
Знай, що твої крила -
Тато твій і мати.

Спи, ласкава крихітка,
Спи, веснянка лагідна,
Спи, яскрава вигадка,
Спи, солодка ягідка.

Вже дощами вулиця
Добре наніч вмилася.
Спи, нехай все збудеться,
Що тобі наснилося.

У твоє віконечко
Загляда калинонька.
Спи, маленьке сонечко,
Спи, моя дитинонька.

Хай тобі насниться
Білий цвіт акації,
Увісні ти принца
Стрінеш у палаці.

Спи, ласкава крихітка,
Спи, веснянка лагідна,
Спи, яскрава вигадка,
Спи, солодка ягідка.

Вже дощами вулиця
