INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_464436','Ми йдемо далі','Музика: Левко Дутковський Слова: О.Жуков. Виконує: Смерічка, Назарій Яремчук','uk','ukraine_1991',NULL,NULL,'аудіозапис','* тут важко розібрати слова','Мерехтить вночі багаття,
Тихо пісня лине,
Нас з тобою трудне щастя
Вірю не покине.

Приспів:
Ми йдемо далі, і не сумуєм,
Життя багато так нам дарує,
Ми йдемо далі, життя будуєм,
На шлях до сонця сміло крокуєм.

Ми врізаємось у скелі,
Землю скрижанілу,
Тут стають мости у небі,
Набираєм силу.

Приспів.

Ми корчагінців загони,
Довго шлях продовжим,
Вперті, впевпені, нестомні
Батьків славу множим.

Приспів.

І летить тайга одвічна
Піснею натхнення.
Магістраль стає велична,
Рівна сьогодення.*

Приспів.','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_464436'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_464436','Ми йдемо далі','Мерехтить вночі багаття,
