INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_471434','Ой всі Поля Самарськиї не зоряли','(Три Брати Самарськиї). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Українські реліґійні роздуми про Воскресіння, Неволю і Спасіння. Пісні Великодні — Спасительні: світ не по Правді. Пісні-плачі Сокола-Прадіда. Бездільне Своє та Безрідне Ясне Соколя утеряв. То Там спочивали Три Брати Рідненьких. А десь ми поверх всякої міри гріха набрали. Що всі три охотою в Військо виступали. А єсть це нас Отцева-та-матчина Молитва покарала. Що на рубані рани та на стреляні знемогали. Рокове Коло. Стежки до листків про Українські традиції.','Ой всі Поля Самарськиї не зоряли
Тільки вони зоряли
Що в Річки-Самарки
А в Кринички-Салтанки
Де Три Терни Дрібненьких
Два Байраки Зелененьких

То Там спочивали Три Брати Рідненьких
То тим вони спочивали
Що на рубані рани та на стреляні знемогали
Ті нарубані кров''ю ісхожають
Ті настреляні к серцю прилягають
Кулі душу с тілом розлучають

Старший Брат словами промовляє
Братіку мій Середулший-Рідненький
Голубоньку Сивенький
Добре ти вчини
Мого Лука Шовкового тетиву зніми
Козацьку голівку звьяжи
До Річки-Самарки
Криниці-Салтанки
Холодної Води зайди!

То Середулший Брат словами промовляє
Братіку мій Старший-Рідненький
Голубоньку Сивенький
Чи не один Міч рубав
Чи не одні Яничарські Кулі постреляли
Що маю я на собі девьять ран рубаних-широких
А чотирі стріляних-глибоких
Та не так важкі рубані-широкі
Як стріляні-глибокі!

Волися ми Брате
Попросімо ми Найменшого Брата-Тринбача
Войськового Грача
Нехай він жалібненько в Військову Суремку заграє
То будуть Теє Козаки зачувати
Будуть ік нам прибувати
Будем ми до свого Отця-та-матки
[в города християнські покланяти

А вже в нас Отець-і-мати
Все добрість собі мали-б
Та в Чистеє Поле вони вихожали-б
Кошулі Тоненькі
Покривала Біленькі
Вони виношали-б
Наше тіло козацьке хорошенько
[в Чистім Полі поховали-б
Звіру-птиці на поталу не давали-б

То Найменший Брат теє зачуває
Словами промовляє
Братіки мої  Старші-Рідненькі
Голубоньки Сивенькі
Не треба нам Братця в Військову Суремку грати
Козаків до себе турбовати
Не Добре ми Братця самі починали
Що всі три охотою в Військо виступали
Нас Отець-і-мати спиняли
Ми великую гордость в собі мали
Роспрощення не приймали
То не єсть то нас братьця Яничарські Кулі
[в Чистім Полі постриляли
Єсть то нас Отцевські-й-матчини Сльози
[в Чистім Полі побивали

То Правда Панове-Козаки Молодці
Полегла / Трьох Братів голова
Їх Слава Козацька не помре-не-поляже
Слава Богу-й-Морю
Всьому Війську Низовому
Услиш Боже честь і хвалу
Небесному Царю','[''pisni.org.ua'', ''cat:dumy'', ''cat:kozacki'', ''Думи'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_471434'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_471434','Ой всі Поля Самарськиї не зоряли','Ой всі Поля Самарськиї не зоряли
Тільки вони зоряли
Що в Річки-Самарки
А в Кринички-Салтанки
Де Три Терни Дрібненьких
Два Байраки Зелененьких

То Там спочивали Три Брати Рідненьких
То тим вони спочивали
Що на рубані рани та на стреляні знемогали
Ті нарубані кров''ю ісхожають
Ті настреляні к серцю прилягають
Кулі душу с тілом розлучають

Старший Брат словами промовляє
Братіку мій Середулший-Рідненький
Голубоньку Сивенький
Добре ти вчини
Мого Лука Шовкового тетиву зніми
Козацьку голівку звьяжи
До Річки-Самарки
Криниці-Салтанки
Холодної Води зайди!

То Середулший Брат словами промовляє
Братіку мій Старший-Рідненький
Голубоньку Сивенький
Чи не один Міч рубав
Чи не одні Яничарські Кулі постреляли
Що маю я на собі девьять ран рубаних-широких
А чотирі стріляних-глибоких
Та не так важкі рубані-широкі
Як стріляні-глибокі!

Волися ми Брате
Попросімо ми Найменшого Брата-Тринбача
Войськового Грача
Нехай він жалібненько в Військову Суремку заграє
То будуть Теє Козаки зачувати
Будуть ік нам прибувати
Будем ми до свого Отця-та-матки
[в города християнські покланяти

А вже в нас Отець-і-мати
Все добрість собі мали-б
Та в Чистеє Поле вони вихожали-б
Кошулі Тоненькі
Покривала Біленькі
Вони виношали-б
Наше тіло козацьке хорошенько
[в Чистім Полі поховали-б
Звіру-птиці на поталу не давали-б

То Найменший Брат теє зачуває
Словами промовляє
Братіки мої  Старші-Рідненькі
Голубоньки Сивенькі
Не треба нам Братця в Військову Суремку грати
Козаків до себе турбовати
Не Добре ми Братця самі починали
Що всі три охотою в Військо виступали
Нас Отець-і-мати спиняли
Ми великую гордость в собі мали
Роспрощення не приймали
То не єсть то нас братьця Яничарські Кулі
[в Чистім Полі постриляли
Єсть то нас Отцевські-й-матчини Сльози
[в Чистім Полі побивали

То Правда Панове-Козаки Молодці
Полегла / Трьох Братів голова
Їх Слава Козацька не помре-не-поляже
Слава Богу-й-Морю
Всьому Війську Низовому
Услиш Боже честь і хвалу
Небесному Царю');
