INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_469030','Зачекайте, літа','Музика: Анатолій Горчинський Слова: Анатолій Горчинський. Виконує: Віталій Білоножко','uk','ukraine_1991',NULL,NULL,'аудіозапис','Альбом "Давайте разом заспіваєм, браття!".','Зачекайте, літа, на кленовій дорозі,
Поки літо цвіте і п''янить, як вино,
Мої мрії, мов птахи і серце в тривозі,
Бо не хоче летіти у вирій воно.

Приспів:
Мов розкрилений вітер життя за плечима,
Тільки стежку до тебе я зумію знайти,
Поцілуй мої очі своїми очима,
Щоб у них залишились тільки я, тільки ти. | (2)

Зачекайте, літа, у блакиті світання,
У дитинство моє, немов рай голубе.
Наче з юності чую я голос кохання,
І голублю в душі я тебе, лиш тебе.

Приспів.

Зачекайте, літа, ще на дворі не осінь,
А в душі ще весна і ні краплі жалю.
І в зірницях моїх не захмариться просінь,
Я ж до тебе тягнусь, наче вперше люблю.

Приспів.

Зачекайте, літа,
Зачекайте','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_469030'), datetime('now')),datetime('now'));
