INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_471532','Наркотик','Музика: Ті що падають вгору Слова: Ольга Чіркова. Виконує: Ті що падають вгору','uk','ukraine_before_1917',NULL,NULL,'http://tpvg.org.ua/',NULL,'На забутих помилках
Ти шукаєш інший шлях,
Це не твій крок до зірок,
Це отруєний ковток.
І мить летить, як вічність
І ти вже сам не свій,
А потім біль і відчай:
"Чому я це зробив?"
Немає слів і сили
Залишити це все,
Але...

Приспів:
Скажи за раз собі -
"Наркотик" - це слово -
Скажи назавжди "ні".
Наркотик - хвороба -
Сильнішим стань в собі:
"Наркотик? Навіщо це мені?"

Запустити білу смерть
І чекати гарних снів,
Помирати кожну ніч,
І шукати довгих днів.
А мить летить, як вічність,
І ти зовсім не свій,
Твоє життя, як пісня,
В якій немає слів.
Чи цього ти хотів так?
Та знаєш сам, що ні,
Але...

Приспів.

А мить летить, як вічність,
І ти зовсім не свій,
Твоє життя, як пісня,
В якій немає слів.
Чи цього ти хотів так?
Та знаєш сам, що ні,
Але...

Приспів.','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_471532'), datetime('now')),datetime('now'));
