INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_46939','Намалюй мені ніч','Музика: Богдан Весоловський Слова: Микола Петренко. Виконує: Лілія Коструба','uk','ukraine_1991',NULL,NULL,'Богдан Весоловський "Прийде ще час..." Львів "Галицька видавнича спілка" 2001',NULL,'Я до тебе прийду, зупинюся в покорі,
Тільки ти не питай, не хвилюй,
