INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_470930','Через ліс, понад став','Українська народна пісня. Виконує: Рутенія','uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','альбом "Безіменні"','Через ліс, понад став
Йшов сотенний Мирослав,
А за ним, як стіна,
Йшла боївка УПА.

Хто живий, хто живий? -
В ряд ставай, в ряд ставай,
Здобувати, визволяти
Милий рідний край.

Через річку, через брід
Йшов сотенний Медвідь,
А за ним йшов у бій
Наш повстанський рій.

Хто живий, хто живий? -
В ряд ставай, в ряд ставай,
Здобувати, визволяти
Милий рідний край.

Наче бджоли лісові,
Наче шершні люті
Виступають юнаки
Золотом окуті.

Хто живий, хто живий? -
В ряд ставай, в ряд ставай,
Здобувати, визволяти
Милий рідний край.

Серед гір, серед скал
Вів сотенний Остап
Бойових юнаків,
Молодих вояків.

Хто живий, хто живий? -
В ряд ставай, в ряд ставай,
Здобувати, визволяти
Милий рідний край','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_470930'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_470930','Через ліс, понад став','Через ліс, понад став
