INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_472333','На чудовій Україні','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'http://www.fleita.com/','На чудовій Україні квіти розквітають,
Як багато українців Бога ще не знають.
А сьогодні Батьків голос ніжно так лунає,
На весілля Христа-Спаса всіх нас закликає

Припів:
Україно, Україно!
Щастя й мир тобі дарує Бог!
Він Один лиш тільки в силі
Зберегти в час криз і катастроф.

Немов ненька немовлятко Він тебе кохає,
В покаянні йди до Нього - Він той, що прощає.
І серденька свого двері відкрий з середини,
Дасть тобі Христос спасіння і ще й для родини.

Припів.

Християне в нашім краї, просимо вас нині,
Живіть в мирі та любові, як в одній Родині.
Як будем Богу служити, ближнього кохати,
Мальовничий край наш буде Бог благословляти.

Припів.','[''pisni.org.ua'', ''cat:christian'', ''cat:patriotic'', ''Пісні на християнську тематику'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_472333'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_472333','На чудовій Україні','На чудовій Україні квіти розквітають,
Як багато українців Бога ще не знають.
А сьогодні Батьків голос ніжно так лунає,
На весілля Христа-Спаса всіх нас закликає

Припів:
Україно, Україно!
Щастя й мир тобі дарує Бог!
Він Один лиш тільки в силі
Зберегти в час криз і катастроф.

Немов ненька немовлятко Він тебе кохає,
В покаянні йди до Нього - Він той, що прощає.
І серденька свого двері відкрий з середини,
Дасть тобі Христос спасіння і ще й для родини.

Припів.

Християне в нашім краї, просимо вас нині,
Живіть в мирі та любові, як в одній Родині.
Як будем Богу служити, ближнього кохати,
Мальовничий край наш буде Бог благословляти.

Припів.');
