INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_472636','"Бандурист"','("Смерть козака бандуриста"). Музика: Г. Хоткевич... Слова: Коло П. Куліш - О. Афанасьєв - І. Срезневський...','uk','ukraine_before_1917',NULL,'1904','"Думи. Історико-героїчний цикл". Київ, Дніпро, 1982.','До історії одного літературного й наукового шахрайства. Підроблені "смерть і прощання козака з бандурою". 1904: Пчілка про "якусь пляму" Куліша. Здається, що підробленою думою "Бандуриста" названо вперше в замітці Олени Пчілки в "Київській Старині" 1904 р. Заслужена письменниця оголошувала тоді кілька листів Куліша і один лист Жемчужникова до кобзаря Остапа Вересая, і з того приводу спинялася над питанням про відносини Куліша і його сучасників до кобзарів і кобзарського репертуару. Вона звертала увагу на легкодушне поводження Куліша з іменами і текстами кобзарів (О. Пчілка думає, що Куліш деякі думи Вересая звязав з іменем Никоненка, тоді вже покійного). На думку авторки, записи від кобзарів, не названих на ім''я, зроблені десь "на шляху" або "в степу", або від таких кобзарів, яких не можна перевірити, бо вони вже померли, все викликають більші або менші сумніви. Але на її погляд сього не слід вважати за якусь пляму на літературнім імені Куліша, маючи на увазі публіцистичний характер його "Записок". Не можна обвинувачувати його й за "присутність в його виданню сильно "доповнених" редакцій, або і зовсім наново зроблених етнографами як напр. дума "про похід давнього козака" (т.з. Посвистач) і "смерть і прощання козака з бандурою" ("Бандурист"). 1910: "Пляма" не без впливу ― зневіра Єрофеєва. Сей погляд на "Бандуриста" авторка тоді не обґрунтувала і в літературі про думи він пройшов без коментарів, хоч мабуть не був без впливу на пізніші праці. Так, пишучи про сю думу, Єрофеєв сумнівався вже не в окремих її мотивах, як Сумцов і Житецький, але взагалі не вірив у "справжність сеї думи". 1913: Кусок Бандуриста Грінченка в Мелодіях Колесси. Коло того-ж часу, як з''явилася стаття Єрофеєва, в "Мелодіях" Ф. Колесси виринув уривок сеї пісні, записаний від кобзаря Кучеренка. Кучеренко кобзар нового типу, що багато знав з книжок, і сю думу видно перейняв з Грінченкових "Дум кобзарських" [ці "Думи" Грінченка з''являються 1897 р.]. 1920: Колесса "підняв нові сумніви" і про зфабрикованого Бандуриста Метлинського. В пізнішій праці Колесса се сказав виразно, і разом з тим підняв нові сумніви що-до автентичности "Бандуриста". Окрім ріжних стилістичних зауважень, він сим разом звернув увагу на вірш Метлинського "Смерть бандуриста", надрукований у збірнику "Думки і пісні" 1839 р., де розвинена ся сама тема. Колесса подав думку, що "Бандурист" міг бути зфабрикований десь в окруженню Метлинського. 1920: Колесса все таки закінчує... думкою: Бандурист "старовинний, а може й народній". Як аргумент на користь підробки Колесса вказує ще на тривіяльний вираз у думі, зазначений у нього крапками: він у нього викликає сумніви, бо подібних виразів у думах не буває. Але беручи на увагу вже згаданий дослід Сумцова, він все таки закінчує свої міркування думкою, що "основний мотив думи про козака-бандуриста старовинний, а може й народній". 1856―1920: Раптом в "думі" з''являється "...": "право", "додаток" Куліша ― "місце" Афанасьєва? Що-до тривіяльности слід завважити, що в першодруку Афанасьєва і в передруку Метлинського її не було: в "Памятниках" дотичний рядок виглядає так: "А то пропаде моя кобза не за собаку! Лежатиме собі в степу"... Аж у передруку Куліша раптом з''являється: "А то пропаде моя кобза не за собаку Лежатиме сама собі у степу, вивернувши вгору ср..." В "Абетці" Гаццука се нарешті дало ― "вивернувши кругляку!" ― своєрідний епізод з історії потрапляння інтелігенції на народній лад. [У Ревуцького обидва рядки повністю замінено рядками крапок.] Чи додаток був Кулішів, чи се місце:-)Афанасьєв пропустив з огляду на цензуру або на таку високу інституцію як "Императорская Академія", що мала друкувати думу, а потім позволив Кулішеві вставити його в своїй книзі? Чи може Куліш мав якісь особливі права до сеї думи? 1903―1927: Ціла дума і "розлука кобзаря з бандурою" Хоткевича: "бандурист-вояк сидить самотно на могилі". Перше ніж перейти до сього Кулішевого права, мусимо згадати тут ще увагу про сю думу Г. Хоткевича, що не критикуючи й не коментуючи її, дав дуже цікаву вказівку для питання її автентичности. Говорячи про значіння кобзи в українськім побуті, автор звернув увагу на голосіння Запорожця над бандурою, яку він продавав Ригоренкові, в Ригоренковім оповіданню у Куліша ("Записки", т. 1, с. 199), і додає таке завваження: "Заховалася навіть ціла високо поетична, художня дума, що представляє той самий момент розлуки кобзаря з бандурою. В сій думі описано, як бандурист-вояк сидить самотно на могилі", і наведено уривок з "Бандуриста". Жаль за кобзу Запорожця і за Колессу. Подібність ситуації, загального тону сього плачу над бандурою в думі і в голосіннню Запорожця дійсно б''є просто в очі, і сама собою піддає думку про спільність їх походження. Хоткевич сеї аналогії не розвинув, але дивно, як се ніхто з раніших дослідників не звернув на неї уваги і не включив її в аргументи в міркуваннях про автентичність чи не-автентичність "Бандуриста". Бо коли-б ся дума була зовсім певна й була відома кобзарям, то ся її аналогія з плачем Ригоренка давала-б надзвичайно цікавий матеріял для питання про генезу дум взагалі. Коли-ж вона додається до инших сумнівів про автентичність думи про "Бандуриста", то ся аналогія стає важною вказівкою на те, де саме шукати властивого джерела сеї сумнівної думи: се джерело мусіло бути в таких сторонах, де могли чути або знати Ригоренкове оповідання про голосіння Запорожця. Збіг обставин здавався нам таким обтяжливим, що в рецензії на збірник Ф. Колесси ми висловили жаль, що авторитетний знавець дум умістив у популярній збірці таку непевну думу. 1926: "Право", "любов", "амбіції", "честь" і "..." Куліша. Але раптом серед сих сумнівів з''явилось повне прояснення на дуже простий і надзвичайно ефектовний лад: 18 травня 1926 р. на однім з прилюдних засідань Укр. Академії Наук Олена Пчілка в доповіді про зустріч з Кулішем познайомила громадянство з такими фактами, що 22 роки тому казали їй заперечити автентичність "Бандуриста", так несподівано, як могло здаватися тоді. Вона навела незвичайно інтересну заяву Куліша в справі фальшованих дум і сеї думи спеціяльно! Нам не довелося бути на сім засіданню, і сі відомості ми завдячуємо Ф.Я. Савченкові, що ласкаво записав для нас відповідні місця з доповіді Олени Пчілки. Зустріч сталася при нагоді археологічного з''їзду в Київі в Драгоманових: мова була про "Историческія пђсни", що були тоді новиною, і про думки видавців про фальшовані думи, які очевидно належали до сенсації сеї публікації. Раптом Куліш урочисто попросив слова і стоячи зложив таку, сказати-б, літературну сповідь: Так ми підробляли і доробляли думи! ― але ми не фальшивомонетчики, що мають користь з фальшування. Товариші Куліша, казав він, фальшували думи так, як Піґмаліон, не знаходячи в житті ідеальної жінки, вирізьбив собі статую і покохавши її, оживив своєю любов''ю. Вони сами прикрашали народню поезію, щоб бачити її ще кращою, сами вливали в неї те, що прагнули в ній бачити. При тім вони нехтували свою авторську амбіцію і віддавали народові твори, що часом могли зробити честь імені не аби-якого поета. І для прикладу Куліш назвав "Бандуриста"... Він не назвав автора сеї думи і нам лишаються в сій галузі тільки здогади. Але ми вдячні і за голий факт, що остаточно розвязує питання про фальшованість сеї думи, що не могла оповісти сама про себе так ясно, як підробки Срезневського або Шишацького-Ілліча, що своєю недоладністю зраджували своє ненароднє походження. Можемо думати, що Куліш з особливим патосом кинув сей заголовок тому, що "дума про бандуриста" не потрапила до реєстру фальшованих дум Антоновича і Драгоманова і можливо, що не вважаючи на сю заяву, в слухачів все таки лишились ще якісь сумніви, і "Бандуриста" зараховано до "дороблених", а не підроблених дум. Тому пізніш і трактовано її як думу з народнім мотивом у замітці Сумцова і в "Мысляхъ" Житецького, і так і не вийнято її з-поміж творів народнього походження. Се розуміється пояснюється тим, що "Бандурист" як композиція в думовім стилю перевищує всі попередні спроби. Але порівняння сеї "думи" з плачем Запорожця дає нам змогу вияснити її літературне походження і без "основного народнього мотиву". 1929: Віктор Петров. Пантелеймон Куліш у п''ятдесяті роки. Життя, ідеологія, творчість. "Вихідний пункт: любов до народности й наукова точність"? Етнографізм і "Малороссия" як привід "організації літературної мови", "службовий момент". Підробки Куліша і непевність "Записок" для наших дослідників. Тьма Макферсонів укр. народу. 2001: Гр. Грабович про макферсонів. Злощасний Бандурист знаходить дорогу! Мала книжка кобзаря Грінченка: шахрайство, плагіат, маніпуляції? "Помогли" народу в "шуканню нових доріг"? "Думи кобзарські". В передмові до третього тому Матеріялів Грінченко між иншим підняв питання про псування українських пісень, про занепад народнього пісенного репертуару, і докірливо запитав, що робить інтелігенція, щоб запобігти тому. "Що зробили ми для того, щоб заховати серед народу кращі зразки народньої творчости? Чим помогли ми народу в його шуканню нових доріг у сій сфері?" В сих словах чуємо відгомін ідеї поетичного обміну інтелігенції з народом, що мав перед собою Куліш, друкуючи "Україну", ― і дійсно Грінченко пішов за сим прикладом: він сам надрукував збірку дум для народу, що мала підтримувати в народі епічну думову традицію, подібно як то уявляв собі Куліш, тільки в инших трохи, більш критичних формах. 1897: "Додатки", "Думи кобзарські" Грінченка. Книжка називалася "Думи Кобзарські". На 106-и сторінках тут було надруковано 18 дум, без коментарів або якого-небудь попередження від видавця. Тексти ― се здебільшого передруки; часом складані ― зложені з відомих варіянтів самим видавцем. Деякі мають замітки про те, що даний текст записаний від такого ось кобзаря, або в такій ось губернії, деякі не мають ніякої помітки ― се переважно Кулішеві зложені тексти, надруковані в першім томі його "Исторіи Возсоединенія Руси". Трапляються і справжні неточності в означенню: напр., дума про Хведора Безрідного означена як дума записана від Вересая, тимчасом текст має додатки, що зробив сам Грінченко. Так само перероблені і Самарські брати. Зложена і Корсунська баталія і дума про смерть Хмельницького. Думы Кобзарськи. Выдано пидъ доглядом Б. Гринченка. У Чернигови 1897. Зміст книжки такий: 1) Про вдову і трьох синів. 2) Про сестру та брата ― обидві від "Кобзаря (!) Архипа Никоненка з Полтавської губ.", себ-то з Записок о Южной Руси. 3) Невольницкий плач. 4) Невольницький плач 2 ― без помітки, обидва зложені тексти Куліша. 5) Про Марусю Богуславку "від Ригоренка", з "Записок". 6) Про трьох братів Озівських, Куліша. 7) Про Кішку Самійла ― "записано у Полтавщині". 8) Про Олексія Поповича, Куліша. 9) Про козака Голоту ― також. 10) Про Хведора Безрідного "записано од кобзаря Остапа Вересая" ― з поправками. [В дійсності ж се текст зложений з варіянтів "Б" (Цертелевъ 1814. Текст записав він сам від невідомого кобзаря мабуть на Миргородщині 1814 р.) і "Ґ" (Записки Ю.-З. Отдђла И.Р.Г.О. т. І 1873 с. 18. Текст записав О. Русов від Остапа Вересая). ― Сей текст, вар. "Х" зложений з вар. "Ґ" і йому додано початок з "Б". ― Текст має додатки, що зробив сам Грінченко:-)] 11) Про трьох братів коло Самари ― зложений текст без помітки. 12) Хмельницький та Барабаш ― від Шута й Бешка. 13) Про Жидів-Рандарів ― від Шута (за Кулішем). 14) Корсунська баталія ― зложений текст без помітки. 15) Смерть Богдана Хмельницького ― також. 16) Про Хвеська Андибера ― від Шута, себ-то Бешка й Шута. 17) Івась Удовиченко ― від Шута. 18) Про смерть козака-бандуриста ― "Од бандуриста с Полтавської губ.". Вона встигла дійсно досить глибоко увійти. Кінець-кінцем книжечка мало замітна, але мала значіння через ту популярність, що вона собі здобула серед народу. Бо за недовгий час вона встигла дійсно досить глибоко увійти в кобзарські круги і відбитись на кобзарськім репертуарі більш ніж яка инша. Ми декілька разів звертали увагу на поворіт деяких старших записів дум з етнографічних збірок назад до кобзарів, і відмічали ті наслідки, що мав сей процес: зат','На татарських полях
Та на козацьких шляхах
То ж не вовки-сіроманці
Квилять та проквиляють,
Не орли-чорнокрильці клекочуть,
Попід небесами літають, -
То ж сидить на могилі
Козак старесенький,
Як голубонько сивесенький,
Та на бандуру грає-виграває,
Голосно-жалібно співає.
Гей, і кінь же біля його
Постріляний та порубаний,
І ратища поламані,
І в ладівниці - ні днісенького [набою].
І [піхви] - без шаблі булатної,
Тільки осталася козакові бандура подорожня,
Та в глибокій кишені тютюну півпапушки,
Та люлька-бурулька.
Гей, сидить же кобзар на могилі,
І люлечку потягає,
І на бандурі грає-виграває,
І голосно-жалібно співає:
"Гей, панове-молодці,
Козаки-запорожці!
Ой де ж то ви пробуваєте?
Чи до Січі-матері приїжджаєте,
Чи ляхів-ворогів киями покладаєте,
Чи татар-бусурмен
Малахаями, як череду, в плін завертаєте?
Гей, коли б же мені бог поміг
Старі ноги розправляти
Та й за вами поспішати,
Хоч би я на останку віку вам заіграв
Та голосно жалібно заспівав.
Гей, уже ж, видно, мені без бандури пропадати,
Уже нездужаю по степах я чвалати;
Будуть мене вовки-сіроманці зустрічати
І дідом за обідом коня мого заїдати..."
Сидить козак на могилі,
На кобзі грає-виграває,
Жалібно співає:
"Гей, кобзо моя,
Дружино моя,
Бандуро моя мальована!
Де ж мені тебе діти:
А чи в чистому степу спалити
І попілець на вітер пустити,
А чи на могилі положити?
А будуть буйні вітри по степу пролітати,
Твої струни зачіпати
І жалібно вигравати,
І будуть козаки подорожні проїжджати,
І твій голос зачувати,
І до могили будуть привертати..."','[''pisni.org.ua'', ''cat:dumy'', ''Думи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_472636'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_472636','"Бандурист"','На татарських полях
Та на козацьких шляхах
То ж не вовки-сіроманці
Квилять та проквиляють,
Не орли-чорнокрильці клекочуть,
Попід небесами літають, -
То ж сидить на могилі
Козак старесенький,
Як голубонько сивесенький,
Та на бандуру грає-виграває,
Голосно-жалібно співає.
Гей, і кінь же біля його
Постріляний та порубаний,
І ратища поламані,
І в ладівниці - ні днісенького [набою].
І [піхви] - без шаблі булатної,
Тільки осталася козакові бандура подорожня,
Та в глибокій кишені тютюну півпапушки,
Та люлька-бурулька.
Гей, сидить же кобзар на могилі,
І люлечку потягає,
І на бандурі грає-виграває,
І голосно-жалібно співає:
"Гей, панове-молодці,
Козаки-запорожці!
Ой де ж то ви пробуваєте?
Чи до Січі-матері приїжджаєте,
Чи ляхів-ворогів киями покладаєте,
Чи татар-бусурмен
Малахаями, як череду, в плін завертаєте?
Гей, коли б же мені бог поміг
Старі ноги розправляти
Та й за вами поспішати,
Хоч би я на останку віку вам заіграв
Та голосно жалібно заспівав.
Гей, уже ж, видно, мені без бандури пропадати,
Уже нездужаю по степах я чвалати;
Будуть мене вовки-сіроманці зустрічати
І дідом за обідом коня мого заїдати..."
Сидить козак на могилі,
На кобзі грає-виграває,
Жалібно співає:
"Гей, кобзо моя,
Дружино моя,
Бандуро моя мальована!
Де ж мені тебе діти:
А чи в чистому степу спалити
І попілець на вітер пустити,
А чи на могилі положити?
А будуть буйні вітри по степу пролітати,
Твої струни зачіпати
І жалібно вигравати,
І будуть козаки подорожні проїжджати,
І твій голос зачувати,
І до могили будуть привертати..."');
