INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_472539','Іван Богун',NULL,'uk','ukraine_before_1917',NULL,NULL,'"Думи. Історико-героїчний цикл". Київ, Дніпро, 1982.',NULL,'У Вінниці на границі,
Під могилою над Бугом-рікою -
Там стояв Іван Богун вільницький
Під обителем-монастирем кальницьким.
Під кальницькою обителлю
Богун стояв,
Із турками-пашами,
Крулевськими ляхами,
Камлицькими князями
Богун воював!
Силу він ляхів-турків стріляв
І шабельками рубав,
На аркан забирав,
В річку Буг їх утопляв.
А ляський круль
І турецький коноїд-паша,
Нехрещена душа,
Силу війська збирали
Івана Богуна і його войсько
Хмарою бусурменською обступали.
Веселились ляхи-турки,
Круль і князь раділи,
Що обложили Богуна
На довгі неділі.
Обступили ляхи-турки,
Кругом обложили,
Козаченьків Богунових голодом морили.
Три тяжкі неділі
Богун з військом
У тяжкій облозі бував...
Од свого ума білими руками
Хмельницькому листа писав,
Богун у Хмельницького батьківської поради питав
Та собі підмоги з Чигрина прохав:
"Просю бога й тебе,
Дай помочі, порадь і повесели нас!..
Бо вже нас ляхи й турки обступають,
Кругом знаменами своїми обкидають,
І кругом нас облягають,
І дуже сильно побіждають".
Як Хмельницький [цеє] зачуває,
До Вінниці за штири доби прибуває.
Його військо гетьманськеє морем нахлинає,
Турецько-польське крульське військо зничтожає,
Богуна з козаками з неволі визволяє.
А сам Хмельницький
До Богуна під''їжджає
І словами промовляє:
"Не сам бог вас спасав -
І я не менше помагав!"
Іван Богуп відмовляє:
"Слава богу і хвала гетьману,
Що не дав нас у неволю, ляхам на поталу!"
Все козацтво
І вояцтво
У ряди ставало,
На всі голоси кричало,
Промовляло,
А кобзарі грали,
В струни дотинали
Та Богдана із Богуном
Піснями хваляли!','[''pisni.org.ua'', ''cat:dumy'', ''Думи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_472539'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_472539','Іван Богун','У Вінниці на границі,
Під могилою над Бугом-рікою -
Там стояв Іван Богун вільницький
Під обителем-монастирем кальницьким.
Під кальницькою обителлю
Богун стояв,
Із турками-пашами,
Крулевськими ляхами,
Камлицькими князями
Богун воював!
Силу він ляхів-турків стріляв
І шабельками рубав,
На аркан забирав,
В річку Буг їх утопляв.
А ляський круль
І турецький коноїд-паша,
Нехрещена душа,
Силу війська збирали
Івана Богуна і його войсько
Хмарою бусурменською обступали.
Веселились ляхи-турки,
Круль і князь раділи,
Що обложили Богуна
На довгі неділі.
Обступили ляхи-турки,
Кругом обложили,
Козаченьків Богунових голодом морили.
Три тяжкі неділі
Богун з військом
У тяжкій облозі бував...
Од свого ума білими руками
Хмельницькому листа писав,
Богун у Хмельницького батьківської поради питав
Та собі підмоги з Чигрина прохав:
"Просю бога й тебе,
Дай помочі, порадь і повесели нас!..
Бо вже нас ляхи й турки обступають,
Кругом знаменами своїми обкидають,
І кругом нас облягають,
І дуже сильно побіждають".
Як Хмельницький [цеє] зачуває,
До Вінниці за штири доби прибуває.
Його військо гетьманськеє морем нахлинає,
Турецько-польське крульське військо зничтожає,
Богуна з козаками з неволі визволяє.
А сам Хмельницький
До Богуна під''їжджає
І словами промовляє:
"Не сам бог вас спасав -
І я не менше помагав!"
Іван Богуп відмовляє:
"Слава богу і хвала гетьману,
Що не дав нас у неволю, ляхам на поталу!"
Все козацтво
І вояцтво
У ряди ставало,
На всі голоси кричало,
Промовляло,
А кобзарі грали,
В струни дотинали
Та Богдана із Богуном
Піснями хваляли!');
