INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_47338','Птахи','Музика: Скрябін Слова: Скрябін. Виконує: Скрябін','uk','ukraine_1991',NULL,NULL,'текст- http://skryabin.ru','Підбір акордів: smash, bohdanko','Раз високо в небі
Я зустрів чужих птахів
Всі вони летіли
Звідтам де і я хотів

Крилами шуміли
Наганяли дикий страх
Потім в воду сіли
Просто в мене на очах

Приспів:
I я собі захотів
Політати десь під небом
Двоє гарних крил
I мені вже ніц не треба
Я собі захотів
Подивитися на люди
З висоти птахів
Я побачив то шо буде

На старих деревах
Вони мають свої хати
То не є далеко
Та не можна їх дістати

Вони мають крила
I не роблять зла нікому
А як стане зимно
То летять собі додому

Приспів.

Далі - варіації на тему приспіву:)','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_47338'), datetime('now')),datetime('now'));
