INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_470137','Тече річка невеличка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'записано з родинного виконання',NULL,'Тече річка невеличка, я не можу перейти,
Не пускає мене мати до бідного сироти.      | (2)

