INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_473930','Наша мова','Музика: Ігор Демарін Слова: Юрій Рибчинський. Виконує: Тріо Либідь','uk','ukraine_1991',NULL,NULL,NULL,'1. Тріо "Либідь". 2. Лідія Михайленко, Ірина Шведова, Ігор Демарін','Мова, наша мова, мова кольорова,
В ній гроза травнева, тиша вечорова.
Мова наша, мова - літ минулих повість,
Вічно юна мудрість, сива наша совість | (2)

Мова, наша мова - мрійнику - жар-птиця,
Грішнику - спокута, спраглому - криниця.
А для мене, мово, ти - як синє море,
У якому тоне і печаль, і горе         | (2)

Мова наша, мова - пісня стоголоса:
Нею мріють весни, нею плаче осінь.
Нею марять зими, нею кличе літо,
В ній криваві рими, сльози "Заповіту" | (2)

Я без тебе, мово, - без зерна полова,
Соняшник без сонця, без птахів діброва.
Як вогонь, у серці я несу в майбутнє
Незгасиму мову, слово незабутнє       | (2)','[''pisni.org.ua'', ''cat:patriotic'', ''cat:pisni-pro-movy'', ''Патріотичні пісні'', ''Пісні про рідну мову'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_473930'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_473930','Наша мова','Мова, наша мова, мова кольорова,
В ній гроза травнева, тиша вечорова.
Мова наша, мова - літ минулих повість,
Вічно юна мудрість, сива наша совість | (2)

Мова, наша мова - мрійнику - жар-птиця,
Грішнику - спокута, спраглому - криниця.
А для мене, мово, ти - як синє море,
У якому тоне і печаль, і горе         | (2)

Мова наша, мова - пісня стоголоса:
Нею мріють весни, нею плаче осінь.
Нею марять зими, нею кличе літо,
В ній криваві рими, сльози "Заповіту" | (2)

Я без тебе, мово, - без зерна полова,
Соняшник без сонця, без птахів діброва.
Як вогонь, у серці я несу в майбутнє
Незгасиму мову, слово незабутнє       | (2)');
