INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_47436','Смутний вечір','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна лірика.',NULL,'Смутний вечір, смутний ранок,
Десь поїхав мій коханок.
Десь поїхав та й бариться,
Серце ж моє печалиться.
Десь поїхав та й немає,
Серце ж моє умліває.
Ой вийду я на той ганок,
Чи не їде мій коханок.
Ой він їде, а я бачу,
Він сміється, а я плачу.
Він сміється ще й моргає,
Нагайкою коня крає.
Нагайкою коня крає,
Всю Вкраїну об''їжджає.
Як об''їхав всю Вкраїну,
Пустив коня на долину.
Пустив коня на долину,
А сідельце під калину.
А сідельце під калину,
Сам ліг спати на годину.
Спав годину, спав другую,
Ще й третюю щасливую.
Добра була годинонька,
Що прибула дівчинонька.
Та й боїться приступити,
Щоб козака не збудити.
Та вирвала травиченьку,
Та вдарила по личеньку:
"Вставай, козак, годі спати,
Бо йдуть турки коня брати.
Бо йдуть турки з татарами,
Возьмуть коня з поводами.
Возьмуть коня ще й сідельце,
Тебе заб''ють, моє серце.
Возьмуть коня - другий буде,
Тебе заб''ють - то жаль буде.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_47436'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_47436','Смутний вечір','Смутний вечір, смутний ранок,
Десь поїхав мій коханок.
Десь поїхав та й бариться,
Серце ж моє печалиться.
Десь поїхав та й немає,
Серце ж моє умліває.
Ой вийду я на той ганок,
Чи не їде мій коханок.
Ой він їде, а я бачу,
Він сміється, а я плачу.
Він сміється ще й моргає,
Нагайкою коня крає.
Нагайкою коня крає,
Всю Вкраїну об''їжджає.
Як об''їхав всю Вкраїну,
Пустив коня на долину.
Пустив коня на долину,
А сідельце під калину.
А сідельце під калину,
Сам ліг спати на годину.
Спав годину, спав другую,
Ще й третюю щасливую.
Добра була годинонька,
Що прибула дівчинонька.
Та й боїться приступити,
Щоб козака не збудити.
Та вирвала травиченьку,
Та вдарила по личеньку:
"Вставай, козак, годі спати,
Бо йдуть турки коня брати.
Бо йдуть турки з татарами,
Возьмуть коня з поводами.
Возьмуть коня ще й сідельце,
Тебе заб''ють, моє серце.
Возьмуть коня - другий буде,
Тебе заб''ють - то жаль буде.');
