INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_47535','Зібралися всі бурлаки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна лірика.',NULL,'Зібралися всі бурлаки
До рідної хати:
Тут нам мило, тут нам любо
З журби заспівати!
Ти, царице Катерино,
Що ти наробила?
Край веселий, край зелений
Панам роздарила!
Багатому розпродала
Від краю до краю,
А бідному зоставила
Те, що поховають.
Бо цариця Катерина
Добре в карти грала,
Вона наше усе добро
Та й попрогравала.
А ти, графе, ти, Потоцький,
Розпроклятий сину,
Занапастив свою Польщу
Та взяв Україну,
Думав було на Вкраїні
Щоб королем стати,
Пропадеш ти тепер сам
Та ще й твоя мати.
Грай же котрий на сопілку, -
Сумно так сидіти,
Що діється тепер в світі
Да чиї ж ми діти.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_47535'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_47535','Зібралися всі бурлаки','Зібралися всі бурлаки
До рідної хати:
Тут нам мило, тут нам любо
З журби заспівати!
Ти, царице Катерино,
Що ти наробила?
Край веселий, край зелений
Панам роздарила!
Багатому розпродала
Від краю до краю,
А бідному зоставила
Те, що поховають.
Бо цариця Катерина
Добре в карти грала,
Вона наше усе добро
Та й попрогравала.
А ти, графе, ти, Потоцький,
Розпроклятий сину,
Занапастив свою Польщу
Та взяв Україну,
Думав було на Вкраїні
Щоб королем стати,
Пропадеш ти тепер сам
Та ще й твоя мати.
Грай же котрий на сопілку, -
Сумно так сидіти,
Що діється тепер в світі
Да чиї ж ми діти.');
