INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_475230','Ой, спи дитя','Українська народна пісня. Виконує: Росава','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, спи, дитя, в колисонці,
Як горошок в билиноньці.
Буде вітрець повівати
Та й горошком колихати...

Як горошок загуркоче,
Дитинонька спати схоче,
