INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_476032','Хочу я з Тобою жить',NULL,'uk','ukraine_1991',NULL,NULL,'пісенник для християнської молоді "Боже, мій Боже, з тобою пісня..."',NULL,'Хочу я з Тобою жить...
Спасе Ти мій дорогий,
Хочу я Тобі служить
Кожен день земний.

Приспів:
Миру без Тебе нема,    |
Щастя без Тебе дріма,  |
Світло лиш в Тобі сія, |
Вічність Ти моя.       | (2)

У неволі я гріха,
Ти мене з гріха звільнив,
Мертвим був, а Ти мене
З мертвих воскресив.
З серцем не борюся я,
Де спічне душа моя,
Лиш в тобі, де всіх Твоїх
Світ дітей святих.

Приспів.

На Голгофі Ти страждав,
Кров свою святу проляв,
В муках Ти тяжких вмирав,
Світ Тя не жалів.
Хочу, Господи, як Ти,
Хрест нести аж до мети,
Твердо знаю й вірю я:
Путь в Тобі моя.

Приспів.','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_476032'), datetime('now')),datetime('now'));
