INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4736','Виростеш Ти Сину вирушиш в Дорогу','(Лебеді материнства). Музика: Платон Майборода, Анатолій Пашкевич Слова: Василь Симоненко. Виконує: Народний хор КНУКіМ, Рената Бабак, Капела бандуристів імені Тараса Шевченка, Юрій Йосифович','uk','ukraine_1991',NULL,'2009','1. Пісневир. Молодіжний співаник. Львів 2001 2. Сто улюблених пісень. Упорядкування, вступна стаття І. І. Осташа. - К.: Музична Україна, 1992. - 240 с. 3. В. Симоненко. У твоєму імені живу. - К.: Веселка, 1994.','*Текст пісні - частина поезії "Лебеді материнства" Василя Симоненка. Тональність поданих акордів Dm відмінна від тональності C#m у доданих файлах. ================================================== Виконавці: Український народний хор Київського національного університету культури і мистецтв, диригент Станіслав Павлюченко, соло: Тетяна Волянська (сопрано) і Галина Фенко (альт), вірші В. Симоненка читає Олександр Кравченко. Запис здійснено Національною радіокомпанією України (НРКУ) у 2009 р.','Виростеш ти, сину, вирушиш в дорогу,
Виростуть з тобою приспані тривоги.
За тобою завжди будуть мандрувати      |
Очі материнські і білява хата.         | (2)
І якщо впадеш ти на чужому полі,
Прийдуть з України верби і тополі.
Стануть над тобою, листям затріпочуть, |
Тугою прощання душу залоскочуть.       | (2)
Можна вибрать друга і по духу брата,
Лиш не можна, сину, матір вибирати.
Можна все на світі вибирати, сину,     |
Вибрати не можна тільки Батьківщину.   | (2)
ЛЕБЕДІ МАТЕРИНСТВА*
Мріють крилами з туману лебеді рожеві,
Сиплють ночі у лимани зорі сургучеві.
Заглядає в шибку казка сивими очима,
Материнська добра ласка в неї за плечима.
Ой біжи, біжи, досадо, не вертай до хати,
Не пущу тебе колиску синову гойдати.
Припливайте до колиски, лебеді, як мрії,
Опустіться, тихі зорі, синові під вії.
Темряву тривожили криками півні,
Танцювали лебеді в хаті на стіні,
Лопотіли крилати і рожевим пір''ям,
Лоскотали марево золотим сузір''ям.
Виростеш ти, сину, вирушиш в дорогу,
Виростуть з тобою приспані тривоги.
У хмельні смеркання мавки чорноброві
Ждатимуть твоєї ніжності й любові.
Будуть тебе кликать у сади зелені
Хлопців чорночубих диво-наречені.
Можеш вибирати друзів і дружину,
Вибрати не можна тільки Батьківщину.
Можна вибрать друга і по духу брата,
Та не можна рідну матір вибирати.
За тобою завше будуть мандрувати
Очі материнські і білява хата.
І якщо впадеш ти на чужому полі,
Прийдуть з України верби і тополі.
Стануть над тобою, листям затріпочуть,
Тугою прощання душу залоскочуть.
Можна все на світі вибирати, сину,
Вибрати не можна тільки Батьківщину.','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4736'), datetime('now')),datetime('now'));
