INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_477236','Од Кракова за воячка мене взяли','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','альбом "Карпатія. Еьнічна музика України"','Од Кракова за воячка мене взяли,
В армійові мої власи стригали.

Мої власи на коліна падали,                     |
Отець, мати і фраїрка плакали.                  | (2)

Отець, мати і фраїрка, не плачте,
Ліпше ви ся пану Богу помольте.

Як надлетить куля, як надлетить кульочка,       |
Я ся скочу, як на небі звіздочка.               | (2)

Юж мі грають, юж мі грають бубни,
Юж мі браття куферочок готують.

Престаньте мі грати, престаньте мі бубни грати, |
Най си піду зо свой милой пожегнать.            | (2)

Іще піду до цвинтаря нового,
Пожегнати свого яня старого.

Вставай, отче старий, з того гробу нового,      |
Взяли сина за воячка твойого.                   | (2)','[''pisni.org.ua'', ''cat:rekrutski'', ''Рекрутські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_477236'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_477236','Од Кракова за воячка мене взяли','Од Кракова за воячка мене взяли,
В армійові мої власи стригали.

Мої власи на коліна падали,                     |
Отець, мати і фраїрка плакали.                  | (2)

Отець, мати і фраїрка, не плачте,
Ліпше ви ся пану Богу помольте.

Як надлетить куля, як надлетить кульочка,       |
Я ся скочу, як на небі звіздочка.               | (2)

Юж мі грають, юж мі грають бубни,
Юж мі браття куферочок готують.

Престаньте мі грати, престаньте мі бубни грати, |
Най си піду зо свой милой пожегнать.            | (2)

Іще піду до цвинтаря нового,
Пожегнати свого яня старого.

Вставай, отче старий, з того гробу нового,      |
Взяли сина за воячка твойого.                   | (2)');
