INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_477131','А за нашов стодолов','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Карпатія (альбом: Етнічна музика України).','А за нашов стодолов купа сена,
