INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_47838','Старій бабі дати граблі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'З репертуару одного львівського лемківського хору.',NULL,'Старій бабі дати граблі,
