INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_479735','Ой на Івана Купайлечка','Українська народна пісня. Виконує: ТаРУТА','uk','ukraine_before_1917',NULL,NULL,NULL,'Літературна вставка: Якби мені крила, Ангельськії крила, То я б слід за сонцем, У твоє віконце полетів. Першим ясним променем, Вуст твоїх торкнувся би І теплом весіннім Тіло твоє й душу зігрівав. Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Ой на Івана Купайлечка,
Там купалася ластівочка.
На бережечку сушілася,
Молода дівка журилася.

Якби мені крила,
Ангельськії крила,
То я б слід за сонцем,
У твоє віконце полетів.

Першим ясним променем,
Вуст твоїх торкнувся би
І теплом весіннім
Тіло твоє й душу зігрівав.

Ще я рушничків не надбала,
Йа вже хлопчика сподобала
Ще я рушничків не нашіла,
Йа вже хлопчика полюбила','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_479735'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_479735','Ой на Івана Купайлечка','Ой на Івана Купайлечка,
