INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_47735','Чом, чом, земле моя','Музика: Денис Січинський Слова: Віра Лебедова. Виконує: Дмитро Гнатюк, Анатолій Солов''яненко, Народний хор Стежина','uk','ukraine_1991',NULL,NULL,'"Малий бандурист" Львів,1935 рік',NULL,'Чом, чом, чом, Земле моя,
Так люба ти мені, так люба ти мені,
Чом, чом, чом, земле моя,
Чарує так мене краса твоя?

Чим, чим, чим мене манить
Пташні твоєї спів,
Запашний цвіт лісів?
Чим, чим, чим?
Манить мене
Водиця струй твоїх,
Що тут пливе?

Тим, тим, тим!
Дитино, знай,
Бо тут ти вперше світ
Узріла в яри літ;
Тим, тим, тим!
Дитини, знай,
Бо води й ті ліси-
Твій рідний край!

Тут, тут, тут!
Діди твої
Пролили кров свою,
За віру і свободу;
Тут, тут, тут!
Усі твої,
Найближчі серденьку
І дорогі!','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''cat:patriotic'', ''Пісні про красу природи'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_47735'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_47735','Чом, чом, земле моя','Чом, чом, чом, Земле моя,
