INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_48083','Ой ніхто там не бував','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Філарет Колесса "Шкільний співаник"',NULL,'Ой ніхто там не бував,
Де ся явір розвивав,
Ой яворе, явороньку зелененький!

Ой таменька зійшло
Три місяці ясні,
Ой яворе, явороньку зелененький!

Три місяці ясні,
Три молодці красні,
Ой яворе, явороньку зелененький!

Ой таменька зійшло
Три зіроньки ясні,
Ой яворе, явороньку зелененький!

Три зіроньки ясні,
Три дівоньки красні,
Ой яворе, явороньку зелененький!','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_48083'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_48083','Ой ніхто там не бував','Ой ніхто там не бував,
