INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_479634','Вишиванка','Музика: Олександр Злотник Слова: Григорій Булах. Виконує: Дмитро Яремчук','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Україно моя вишиванко
Ти мій біль, моя мука і доля;
Я без тебе як день без світанку,
Я без тебе, як жайвір без поля

Приспів:
Вишиванко моя вишиванко
Смерекова вишнева жага,
Ти далеких Карпат полонянка,
Ти Дніпра мов хвиля жива;
Я по світу іду в вишиванці
Аж дивуються ген журавлі,
Хай встрічають в веселій багрянці
Україна іде по землі.

Україно моя вишиванко
Ти тернова моя голубінь,
Хай святиться навік світлий ранок
І серпневого дня височінь

Приспів','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_479634'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_479634','Вишиванка','Україно моя вишиванко
Ти мій біль, моя мука і доля;
Я без тебе як день без світанку,
Я без тебе, як жайвір без поля

Приспів:
Вишиванко моя вишиванко
Смерекова вишнева жага,
Ти далеких Карпат полонянка,
Ти Дніпра мов хвиля жива;
Я по світу іду в вишиванці
Аж дивуються ген журавлі,
Хай встрічають в веселій багрянці
Україна іде по землі.

Україно моя вишиванко
Ти тернова моя голубінь,
Хай святиться навік світлий ранок
І серпневого дня височінь

Приспів');
