INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_482137','Прощай, дівчино','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1990','1. Співанник для дітей дошкільного та шкільного віку, зладив М. Гайворонський. Львів, 1922. 28 с. 2. Повік не зів''яне. Стрілецькі пісні Михайла Гайворонського. Упор. В. Подуфалий. Тернопіль, 1990.','пісня кубанських козаків, яку переробили УСС','Прощай, дівчино, бо я вже йду, | (2)
Благослови м''я на ту війну.    | (2)

Ударить куля і грудь проб''є,   | (2)
Згадай же мене, дівча моє.     | (2)

Прощай, дівчино, прощай, прощай, | (2)
Бо я іду в бій за рідний край.   | (2)

Летіла куля понад гору,       | (2)
Та й ударила у грудь мою.     | (2)

Потекла кровця річенькою,     | (2)
Аж до тихого Дунаю.           | (2)

В тім Дунаю чиста вода,       | (2)
Вже мого хлопця в світі нема. | (2)','[''pisni.org.ua'', ''cat:strilecki'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_482137'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_482137','Прощай, дівчино','Прощай, дівчино, бо я вже йду, | (2)
Благослови м''я на ту війну.    | (2)

