INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_47481','Ой а в городі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна лірика.',NULL,'Ой а в городі, ой а в городі,
А в городі там случилася біда.
Ой у городі, ой у городі,
Там убили молодого козака.
Ой поховали, да гей, поховали,
Поховали при широкій долині.
Ой насипали, да гей, насипали,
Насипали високую могилу.
Ой посадили, да гей, посадили,
Посадили червоную калину.
Ой налинули, да гей, налинули,
Налинули а все сиві голуби.
Ой удовиний, да гей, удовиний
Широкий двір крилечками замели.
Ой заспівали, да гей, заспівали
Й голосами удівоньку збудили.
"Ой встань, проснися, да гей, встань, проснися,
Встань, проснися, удівонько молода!
Ой встань, послухай, ой встань, послухай,
Встань, послухай, про що люди гомонять!
Ой люди кажуть, ой люди кажуть -
Твого милого на світі вже нема!"
Як вдова вчула, як вдова вчула,
Сіла й тяжко зажурилась молода...','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_47481'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_47481','Ой а в городі','Ой а в городі, ой а в городі,
А в городі там случилася біда.
Ой у городі, ой у городі,
Там убили молодого козака.
Ой поховали, да гей, поховали,
Поховали при широкій долині.
Ой насипали, да гей, насипали,
Насипали високую могилу.
Ой посадили, да гей, посадили,
Посадили червоную калину.
Ой налинули, да гей, налинули,
Налинули а все сиві голуби.
Ой удовиний, да гей, удовиний
Широкий двір крилечками замели.
Ой заспівали, да гей, заспівали
Й голосами удівоньку збудили.
"Ой встань, проснися, да гей, встань, проснися,
Встань, проснися, удівонько молода!
Ой встань, послухай, ой встань, послухай,
Встань, послухай, про що люди гомонять!
Ой люди кажуть, ой люди кажуть -
Твого милого на світі вже нема!"
Як вдова вчула, як вдова вчула,
Сіла й тяжко зажурилась молода...');
