INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_48131','Танок','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Філарет Колесса "Шкільний співаник"',NULL,'Ой, пляшу, пляшу, знаю до кого:
Дасть мені дружечка пів золотого.

Ой, пляшу, пляшу, знаю до кого:
Дасть мені свашенька пів золотого.

