Дасть мені ґаздиня пів золотого.','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_48131'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_48131','Танок','Ой, пляшу, пляшу, знаю до кого:
Дасть мені дружечка пів золотого.

