INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_482481','Ой там на горі вогні горят','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Записано в с. Кирдани Таращанського р-ну Київської обл.',NULL,'Ой там на горі вогні горять,
Ой там Ганнусю перевозять.
