INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_482735','Ой орали хлопці ниву','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Найкращі пісні України, "Майдан", К., 1992.',NULL,'Ой орали хлопці ниву,
Виорали ярмо,
Заплати мені, дівчино,
Чи я ходив дармо?

А я ж тобі, козаченьку,
Ще й переплатила.
Цілував моє личенько —
Я й не боронила.

То при сонцю, то при зорях,
То при місяченьку.
Цілував моє личенько,
Вражий козаченьку.

І коли ми зустрічались —
Сухі дуби цвіли,
І коли ми розлучались —
Зелені пов''яли.

Хай дуби ті повсихають,
Що так рано цвіли,
Хай ті люди щастя не знають,
Що нас розлучили.','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_482735'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_482735','Ой орали хлопці ниву','Ой орали хлопці ниву,
Виорали ярмо,
Заплати мені, дівчино,
Чи я ходив дармо?

А я ж тобі, козаченьку,
Ще й переплатила.
Цілував моє личенько —
Я й не боронила.

То при сонцю, то при зорях,
То при місяченьку.
Цілував моє личенько,
Вражий козаченьку.

І коли ми зустрічались —
Сухі дуби цвіли,
І коли ми розлучались —
Зелені пов''яли.

Хай дуби ті повсихають,
Що так рано цвіли,
Хай ті люди щастя не знають,
Що нас розлучили.');
