INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_481838','Динь, динь, білий динь','(День, день, білий день). Українська народна пісня. Виконує: Ватра, Гурт Кольори Закарпаття','uk','ukraine_before_1917',NULL,NULL,'http://posydenky.lvivport.com',NULL,'Приспів:
Динь, динь, білий динь,      |
Вставай, дівко, клади вгинь. | (2)

Дівка встала, вгинь наклала,
Не є того, што чекала.
Динь, динь, білий динь,
Вставай, дівко, клади вгинь.

Приспів.

Збирай тріски по дворови,
Вари їсти легіньови.
Динь, динь, білий динь,
Вставай, дівко, клади вгинь.

Приспів.

Збирай тріски, най ся курят,
Най ся люде мнов не журят.
Динь, динь, білий динь,
Вставай, дівко, клади вгинь','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_481838'), datetime('now')),datetime('now'));
