INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_479436','Садок вишневий коло хати','Музика: Микола Лисенко, Василь Лютий Слова: Тарас Шевченко. Виконує: Василь Лютий, Рената Бабак','uk','ukraine_1991',NULL,NULL,'1. М. Лисенко. "Пісні та романси" для високого голосу в супроводі фортепіано. "Музична Україна", Київ, 1967.',NULL,'Садок вишневий коло хати,
Хрущі над вишнями гудуть.
Плугатарі з плугами йдуть,
Співають, ідучи, дівчата,
А матері вечерять ждуть.

Сем''я вечеря коло хати,
Вечірня зіронька встає.
Дочка вечерять подає,
А мати хоче научати,
Та соловейко не дає.

Поклала мати коло хати
Маленьких діточок своїх,
Сама заснула коло їх.
Затихло все, тілько дівчата
Та соловейко не затих','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_479436'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_479436','Садок вишневий коло хати','Садок вишневий коло хати,
