INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_479137','Я спасибі долі скажу','(Темна ніч на гори ляже, Серед гір високих). Музика: Богдан Грицак Слова: Богдан Грицак. Виконує: Василь Зінкевич, Іван Попович','uk','ukraine_1991',NULL,NULL,NULL,'Тут слова ще недопрацьовані, виправте будь ласка хто має запис!','Серед гір високих - полонин широких,
Де туман сивіє в далині,
Де весна на плаях, роси розсипає
Доля усміхнулася мені.

Як настане літо і засипле цвітом
Стежку, по котрій до тебе йшов,
Як загляну в очі - молоді дівочі       |
Доки місяць в небі не зійшов.          | (2)

Приспів:
Темна ніч на гори ляже, темна ніч на гори ляже,
Помандрує день за перевали
Я спасибі долі скажу, я спасибі долі скажу,
Що тебе мені подарувала..

В полонинах квіти і голубить вітер,
Пелюстки додолу упадуть,
Хоч вода глибока стрінеться в потоках  |
Все одно до тебе перейду.              | (2)

Приспів','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_479137'), datetime('now')),datetime('now'));
