INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_483389','Ой вишенька, черешенька','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Пісні Явдохи Зуїхи / Запис. Гнат Танцюра. - Київ: Наукова Думка, 1965. - 812 с.',NULL,'Ой вишенька, черешенька,
Чом рясно не родиш?
Молодая дівчинонько,
Чом гулять не ходиш?

Як же мені рясно родити
Між трьома дубами?
Як же мені гуляти ходити
Межи ворогами?

Тепер мені рясно родити
За високим тином.
Тепер мені гуляти ходити
За отецьким сином.

Отецький син гарний та красний,
А вдовин ще кращий.
Ой як вийде на вулицю,
Як той місяць ясний.    Фонограма-мінус (mp3)','[''pisni.org.ua'', ''cat:podilski'', ''Пісні з Поділля'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_483389'), datetime('now')),datetime('now'));
