INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_480532','Прощай слава, город рідненький','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. надіслав Ілля Самойлов',NULL,'Прощай слава, город рідненький,
Прощай, Україно.
Прощай, сад мій зелененький,
Прощай ти, дівчино.

А в тім саду зеленому,
Де сонечко сяє.
На калині біля хати
Соловей співає.

Співай, співай, соловейко,
Сидя на калині.
Не журися, дівчинонько,
У тяжкій годині.

А я піду на край світу,
Буду воювати.
Тебе, моє серденятко,
Буду споминати.','[''pisni.org.ua'', ''cat:kozacki'', ''cat:kubanski'', ''Козацькі пісні'', ''Кубанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_480532'), datetime('now')),datetime('now'));
