INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_483931','Бистра вода','Музика: народ Слова: народ','uk','ukraine_before_1917',NULL,NULL,'Український народний співаник, Мюнхен, 1946 р.',NULL,'Бистра вода, бистра вода
Беріженьки зносить,
Молодий козак, молодий козак
Отамана просить.

Пусти ж мене, отамане,
Із поля до дому,
Бо заплакала, бо затужила
Дівчина за мною.

Пущу тебе, пущу тебе,
Але не самого,
Скажу осідлати, скажу осідлати
Коня вороного.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_483931'), datetime('now')),datetime('now'));
