INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_48434','Ой кум до куми залицявся','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой кум до куми залицявся,
Посіяти конопельки обіцявся.
Він сіяв, присівав,
Присіваючи, казав:
"Ти кума, ти душа,
Ти кругом, кума, ох і хороша!"

Ой кум до куми залицявся,
Вибирати конопельки обіцявся.
Він брав, вибирав,
Вибираючи, казав:
"Ти кума, ти душа,
Ти кругом, кума, ох і хороша!"

Ой кум до куми залицявся,
Вимочити конопельки обіцявся.
Він мочив, примочав,
Примочаючи, казав:
"Ти кума, ти душа,
Ти кругом, кума, ох і хороша!"

Ой кум до куми залицявся,
Витіпати конопельки обіцявся.
Він тіпав, витіпав,
Витіпаючи, казав:
"Ти кума, ти душа,
Ти кругом, кума, ох і хороша!"

Ой кум до куми залицявся,
Випрясти конопельки обіцявся.
Він пряв, випрядав,
Випрядаючи, казав:
"Ти кума, ти душа,
Ти кругом, кума, ох і хороша!"

Ой кум до куми залицявся,
Їй наткати полотна обіцявся.
Він ткав, витикав,
Витикаючи, казав:
"Ти кума, ти душа,
Ти кругом, кума, ох і хороша!"

Ой кум до куми залицявся,
Їй пошити сорочечку обіцявся.
Він шив, вишивав,
Вишиваючи, казав:
"Ти кума, ти душа,
Ти кругом, кума, ох і хороша!"

Ой кум до куми залицявся,
Одягнути сорочечку обіцявся.
Він її одягав,
Одягаючи, казав:
"Ти кума, ти душа,
Ти кругом, кума, ох і хороша!"','[''pisni.org.ua'', ''cat:zhartivlyvi'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_48434'), datetime('now')),datetime('now'));
