INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_485930','Щедрий Вечір Добрий Вечір',NULL,'uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Щедрий Вечір Добрий Вечір
Добрим Людям на Весь-вечір!

А я знаю що Пан Дома
Сидить собі Кінець Стола

Сидить собі Кінець Стола
А на ньому Шуба Люба

А на ньому Шуба Люба
А в Тій Шубі Калиточка

А в Тій Шубі Калиточка
В Тій Калитці Сім Червінців

В Тій Калитці Сім Червінців
Усім Дітям по Червінцю','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:narodni'', ''cat:philosophic'', ''cat:shchedrivky'', ''Колядки'', ''Народні пісні'', ''Філософські пісні'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_485930'), datetime('now')),datetime('now'));
