INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_486389','Нехай сповняться уста наші','Виконує: Ансамбль Львівського Університету "Черемош"','uk','ukraine_1991',NULL,NULL,'аудіозапис','молитва','Нехай сповняться уста наші
Хвалення Твого, Господи!
Бо ми співали, бо ми співали,
Бо ми співали славу, славу Твою.

Бо Ти сподобив нас причаститися
Святих Твоїх, божественних,
Безсмертних і животворящих
Таїн, таїн.

Збережи нас у Твоїй святині
Весь день поучатися правді Твоїй,
Правді, правді Твоїй.
Алилуя, алилуя, алилуя!','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_486389'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_486389','Нехай сповняться уста наші','Нехай сповняться уста наші
Хвалення Твого, Господи!
Бо ми співали, бо ми співали,
Бо ми співали славу, славу Твою.

Бо Ти сподобив нас причаститися
Святих Твоїх, божественних,
Безсмертних і животворящих
Таїн, таїн.

Збережи нас у Твоїй святині
Весь день поучатися правді Твоїй,
Правді, правді Твоїй.
Алилуя, алилуя, алилуя!');
