INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_483532','Купалися ластів''ята','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Пісня записана в с. Соболівка, Теплицького району, Вінницької області від місцевої жительки Волошин Франі Павлівни 1908 р.н.',NULL,'Купалися ластів''ята
Тай в чару - водиці,
Щоб були ми білотілі
Та ще й білолиці.

Купалися ластів''ята
Тай в чару - водиці,
Щоб були ми чорноброві
Та ще й білолиці.

У любистку купалися,
Живу воду пили,
Щоб здоров''я тіло мало-
Горенька не знало','[''pisni.org.ua'', ''cat:podilski'', ''Пісні з Поділля'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_483532'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_483532','Купалися ластів''ята','Купалися ластів''ята
Тай в чару - водиці,
Щоб були ми білотілі
Та ще й білолиці.

Купалися ластів''ята
Тай в чару - водиці,
Щоб були ми чорноброві
Та ще й білолиці.

У любистку купалися,
Живу воду пили,
Щоб здоров''я тіло мало-
Горенька не знало');
