INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_47787','Приїхали три козаки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна лірика',NULL,'Приїхали три козаки,
Та всі три однакі,
Питаються: "Марусенька
У которій хаті?"

Один стоїть край віконця,
Другий коня в''яже,
Третій стоїть під дверима.
"Добрий вечір!" каже.

"Добрий вечір, стара мати,
Дай води напиться,
Пусти дочку на вулицю,
Ой хоч подивиться!" -

"Стоїть вода у ставочку,
Коли хоч - напийся,
Сидить дочка край віконця,
Коли хоч - дивися!" -

"Не погожа в ставу вода. -
Піду до криниці,
Незвичайна дочка твоя, -
Піду до вдовиці!

У вдовиці дві світлиці,
Ще й третя кімната,
А в дівчини одна хата,
Та й та не прибрата.

У вдовиці дві світлиці,
Гарні вечорниці,
Стоять чари заправлені
В горшку на полиці".','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_47787'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_47787','Приїхали три козаки','Приїхали три козаки,
Та всі три однакі,
Питаються: "Марусенька
У которій хаті?"

Один стоїть край віконця,
Другий коня в''яже,
Третій стоїть під дверима.
"Добрий вечір!" каже.

"Добрий вечір, стара мати,
Дай води напиться,
Пусти дочку на вулицю,
Ой хоч подивиться!" -

"Стоїть вода у ставочку,
Коли хоч - напийся,
Сидить дочка край віконця,
Коли хоч - дивися!" -

"Не погожа в ставу вода. -
Піду до криниці,
Незвичайна дочка твоя, -
Піду до вдовиці!

У вдовиці дві світлиці,
Ще й третя кімната,
А в дівчини одна хата,
Та й та не прибрата.

У вдовиці дві світлиці,
Гарні вечорниці,
Стоять чари заправлені
В горшку на полиці".');
