INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_48632','Розлилися круті бережечки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Бібліотека поета. Народна лірика. 2. Українські народні думи та історичні пісні,Київ,"Веселка",1990','Примітки:Записано на початку 70-х рр. ХІХ ст. в с.Мар''янівка, Єлисаветградської губернії. Друк. за вид.: Українські народні думи та історичні пісні.-1955.-с.91 Пісня була складена напередодні або на початку визвольної війни українського народу проти польської шляхти 1648-1654 рр.','Розлилися круті бережечки,
Гей, гей, по роздоллі;
Пожурились славні козаченьки,
Гей, гей, у неволі.
Гей ви, хлопці, ви, добрі молодці,
Гей, гей, не журіться, -
Посідлайте коні воронії,
Гей, гей, садовіться!
Та поїдем у читсеє поле,
Гей, гей, у Варшаву,
Та наберем червоної китайки,
Гей, гей, та на славу!
Гей, щоб наша червона китайка,
Гей, гей, не злиняла,
Та щоб наша козацька слава,
Гей, гей, не пропала!
Гей, щоб наша червона китайка,
Гей, гей, червоніла,
А щоб наша козацька слава,
Гей, гей, не змарніла!
Гей, у лузі червона калина,
Гей, гей, похилилася;
Чогось наша славна Україна,
Гей, гей, засмутилася.
А ми ж тую червону калину,
Гей, гей, та піднімемо;
А ми ж свою славну Україну,
Гей, гей, та розвеселимо!','[''pisni.org.ua'', ''cat:istorychni'', ''cat:kozacki'', ''Історичні пісні'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_48632'), datetime('now')),datetime('now'));
