INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4889','Микита Швачка','Музика: Кому Вниз Слова: Тарас Шевченко. Виконує: Кому Вниз','uk','ukraine_1991',NULL,NULL,'Пісневир. Молодіжний співаник. Львів 2001',NULL,'Ой не п’ється горілочка, не п’ються й меди.
Не будете шинкувати, прокляті жиди.
Ой не п’ється теє пиво, а я буду пить.
Не дам же я вражим ляхам в Україні (добре) жить.

Ходім, батьки-отамани, у Фастів в неділю
Та надінем вражим ляхам кошуленьку білу...
Ні, не білу, а червону... Ходім, погуляєм
Та в пригоді свого батька старого згадаєм.

Прийди з того Межигір’я, наш славний Палію,
Подивися, що той Швачка у Фастові діє!
Добре діє! У Фастові, у славному місті,
Покотилось ляхів, жидів не сто і не двісті.

Покотилось. А майдани кров почервонила.
А оранди з костьолами, мов свічки, згоріли.
В самім замку невеличку церковку святую
Не спалено. Отам Швачка співа алілуя.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4889'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4889','Микита Швачка','Ой не п’ється горілочка, не п’ються й меди.
