INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_49030','Сонцем, небом, дощем','Музика: Марія Бурмака Слова: Марія Бурмака. Виконує: Марія Бурмака','uk','ukraine_1991',NULL,NULL,'http://www.shulga.kiev.ua; аудіо- Марія Бурмака. Міа. 2001',NULL,'Em
Я - де тихо і дощ, серед вулиць і площ,
Серед неба і зір, серед рік, серед гір ...
Em
Я - де втомлений шлях, де вертається птах
Із чужих берегів на дороги свої ...

Приспів:
Сонцем, небом, дощем,
Снігом, вітром, благаю ще -
Тільки, тільки мене
Не залишай ...

Я - де трунок п''янкий,
де слова від руки,
Ті далекі слова,
обертом голова
Від неписаних слів,
від ночей тих і днів,
Що забути не можу
Я - де тихо і дощ ...

Приспів.

Я давно там, де ти,
хай ще довго іти
І летіти дарма.
Де ти є чи нема?
Це не знати мені,
це надія бринить,
Я - де світло і тінь ...
Я - іду по воді ...

Приспів.','[''pisni.org.ua'', ''cat:manrivni'', ''Пісні на мандрівну тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_49030'), datetime('now')),datetime('now'));
