INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_490939','Ой, наорали та насіяли','Музика: народ Слова: народ. Виконує: Народний хор Україна','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой, наорали та насіяли -
Нікому збирати.
Ой, поїхали та чумаченьки
В Молдову гуляти.

Ой, скриплять вози та бряжчать ярма,
Воли ремигають,
А попереду та чумаченьки
На скрипочку грають.

Ой, болять ручки та болять ніжки,
Пшениченьку жнучи,
Ой, як же ж мені та наскучило,
Миленького ждучи.

Ой, нема мого та миленького,
Нема моєй душки:
О, нема кому та постелити
Білої подушки.

Ой, нема мого та миленького,
Нема мого пана:
Ой, а вже ж моя та біла постіль
Порохом припала.','[''pisni.org.ua'', ''cat:chumacki'', ''cat:socialno-pobutovi'', ''Чумацькі пісні'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_490939'), datetime('now')),datetime('now'));
