INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_488930','Старий рік минає','Музика: народ Слова: народ','uk','ukraine_1991',NULL,NULL,'аудіозапис','Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: ― Святі Водорщі) ―: Дівич-Вечір...... Зелені Свята () ― Царинні Містерії...... Астральні Жнива... Рокове Коло.','Старий рік минає,
Новий наступає.
Старий рік минає,   |
Новий наступає,     |
Новий наступає.     | (2)

Прощай, старий роче,
Ми тебе не хочем.
Старий рік минає,   |
Новий наступає,     |
Новий наступає.     | (2)

Ми хочем нового -
Спаса Рожденного.
Старий рік минає,   |
Новий наступає,     |
Новий наступає.     | (2)

А він буде кращим,
Принесе нам щастя.
Старий рік минає,   |
Новий наступає,     |
Новий наступає.     | (2)

І миру на світі,
Здоров''я всім дітям.
Старий рік минає,   |
Новий наступає,     |
Новий наступає.     | (2)','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_488930'), datetime('now')),datetime('now'));
