INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_488137','Бігла Дівонька рано по Воду','Музика: народ Слова: народ','uk','ukraine_before_1917',NULL,NULL,'Колядки і щедрівки. - К.: Музична Україна. - 1991. - 240 с.','Колядка Дівчині. Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Бігла дівонька рано по воду.

Приспів: На Дунай!
На Дунай, Дівонько,
Рано по Воду вибігай!*

З оріховими коновочками.
А з золотими накривочками.
Десь ся зірвали буйнії вітри.
Звійнули єї з рясами вінець.
Побігла она до рибарчиків:
- Три рибарчики, три молодчики!
Ой закиньте ви шовковий невід,
