INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_48737','Ой хто в тому лісі','Українська народна пісня. Виконує: Вогневир','uk','ukraine_before_1917',NULL,NULL,'Ой на Івана та й на Купайла...- Львів: Студентське братство ЛНУ ім.І.Франка, 2002',NULL,'Ой хто в тому лісі стукає-гукає -
калина-малина! Стукає-гукає!
Молодий Іванко деревце рубає,
молода Марися трісочки збирає.
Трісочки збирає, він її питає:
- Чи любиш ти мене, чи підеш за мене?
- Хоч я тебе люблю, за тебе не піду.
А Іванко каже: "Я Ірисю люблю.
Я Ірисю люблю - черевички куплю!"
А Богданко каже: "Я Оксанку люблю.
Я Оксанку люблю - і перстенець куплю!"
А Андрійко каже: "Я Світланку люблю.
Я Світланку люблю - і за себе візьму!"','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_48737'), datetime('now')),datetime('now'));
