INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_491338','"Покотилась зірка з неба"','Музика: Я. Тарасюк Слова: Я. Тарасюк. Виконує: Павло Табаков','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'1.
Народився Бог на сіні
В Вифлеємі десь.
Покотилась зірка з неба -
У старий вертеп.

2.
Старий Йосиф сіно носить,
Сумно зітхає,
А Марія рожденому
Стиха співає.

Приспів:
Спи, дитинонько кохана,
Люлі-люлі, баю-бай.
А ти, місяцю на небі,
В ясла родженому сяй (2).

Програш.

3.
Три царі прийшли вклонитись
Сину Божому
І принесли у дарунок
Ризу золоту.

Даром щастя і любові
Нас благослови,
Щоб у вірі, у Христовій,
Ми усі жили.

Приспів.

Програш.

Повтор 1 куплету.

Покотилась зірка з неба (8).','[''pisni.org.ua'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_491338'), datetime('now')),datetime('now'));
